import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, useGLTF, Environment } from '@react-three/drei';
import { Component, useMemo, useEffect, useState, useRef, useCallback, Suspense } from 'react';
import * as THREE from 'three';
import { SoundManager } from '../Effects/SoundManager';
import ktx2Loader from '../View/ktx2Loader';
import { F_UI, F_TITLE, OG_GRAD, C_BTN_SHADOW, C_CARD_SHADOW } from './uiTheme';
import { useT } from './i18n';
import { useGameStore } from '../Logic/store';
import { GameButton } from './GameCard';

useGLTF.preload('/models/RIO.glb');
fetch('/images/qwantani_mid_morning_puresky_1k.hdr').catch(() => {});

class EnvBoundary extends Component {
    state = { failed: false };
    static getDerivedStateFromError() { return { failed: true }; }
    render() { return this.state.failed ? null : this.props.children; }
}

// ── Конфетти (2D Canvas, ноль React-state) ────────────────────────────────────
const CONFETTI_COLORS = ['#ffd700','#ffaa00','#fff','#ffeeaa','#00d4ff','#ff6b6b','#a8ff78','#ff9ff3'];
const SHAPES = ['square', 'rect', 'circle'];

function _easeOutConfetti(t) {
    return 1 - Math.pow(1 - Math.min(t, 1), 2.5);
}

function _mkParticle(now) {
    const h = window.innerHeight, w = window.innerWidth;
    const side  = Math.random() < 0.5 ? -1 : 1;
    const cx    = w / 2 + side * 80;
    const aMin  = side < 0 ? -Math.PI : -Math.PI / 2 + 0.2;
    const aMax  = side < 0 ? -Math.PI / 2 - 0.2 : 0;
    const angle = aMin + Math.random() * (aMax - aMin);
    const tY    = h * (0.7 + Math.random() * 0.2) * 4;
    const spd   = tY / (Math.abs(Math.sin(angle)) || 0.01);
    return {
        cx, cy: h,
        vx:    Math.cos(angle) * spd,
        vy:    Math.sin(angle) * spd,
        spin:  (Math.random() - 0.5) * 900 * Math.PI / 180,  // rad
        sz:    7 + Math.random() * 9,
        dur:   (2.5 + Math.random() * 1.2) * 1000,           // ms
        color: CONFETTI_COLORS[~~(Math.random() * CONFETTI_COLORS.length)],
        shape: SHAPES[~~(Math.random() * SHAPES.length)],
        start: now + Math.random() * 60,
    };
}

function ConfettiCanvas({ active }) {
    const canvasRef = useRef();
    const rafRef    = useRef();
    const ivRef     = useRef();
    const stopRef   = useRef();
    const ptRef     = useRef([]);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!active) {
            cancelAnimationFrame(rafRef.current);
            clearInterval(ivRef.current);
            clearTimeout(stopRef.current);
            ptRef.current = [];
            canvas.getContext('2d').clearRect(0, 0, canvas.width, canvas.height);
            return;
        }

        canvas.width  = window.innerWidth;
        canvas.height = window.innerHeight;
        const ctx = canvas.getContext('2d');

        const addBatch = () => {
            const now = performance.now();
            for (let i = 0; i < 15; i++) ptRef.current.push(_mkParticle(now));
            if (ptRef.current.length > 180) ptRef.current = ptRef.current.slice(-180);
        };
        addBatch();
        ivRef.current   = setInterval(addBatch, 150);
        stopRef.current = setTimeout(() => clearInterval(ivRef.current), 3000);

        const draw = (now) => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            const alive = [];
            for (const p of ptRef.current) {
                const elapsed = now - p.start;
                if (elapsed < 0)     { alive.push(p); continue; }
                const frac = elapsed / p.dur;
                if (frac >= 1) continue;
                const t  = _easeOutConfetti(frac);
                const pw = p.shape === 'rect' ? p.sz * 0.5 : p.sz;
                const op = frac < 0.8 ? 1 : 1 - (frac - 0.8) / 0.2;
                ctx.save();
                ctx.globalAlpha = op;
                ctx.fillStyle   = p.color;
                ctx.translate(p.cx + t * p.vx, p.cy + t * p.vy);
                ctx.rotate(t * p.spin);
                if (p.shape === 'circle') {
                    ctx.beginPath(); ctx.arc(0, 0, pw / 2, 0, Math.PI * 2); ctx.fill();
                } else {
                    ctx.fillRect(-pw / 2, -p.sz / 2, pw, p.sz);
                }
                ctx.restore();
                alive.push(p);
            }
            ptRef.current  = alive;
            rafRef.current = requestAnimationFrame(draw);
        };
        rafRef.current = requestAnimationFrame(draw);

        return () => {
            cancelAnimationFrame(rafRef.current);
            clearInterval(ivRef.current);
            clearTimeout(stopRef.current);
        };
    }, [active]);

    return (
        <canvas ref={canvasRef} style={{
            position: 'fixed', inset: 0,
            pointerEvents: 'none', zIndex: 2110,
        }} />
    );
}

// ── KTX2 init для отдельного Canvas медали ────────────────────────────────────
function KTX2Init() {
    const { gl } = useThree();
    useEffect(() => { ktx2Loader.detectSupport(gl); }, [gl]);
    return null;
}

// ── Медаль (GLB) ───────────────────────────────────────────────────────────────
function MedalMesh({ groupRef, onMounted }) {
    const { scene } = useGLTF('/models/RIO.glb');
    const [texture, setTexture] = useState(null);

    useEffect(() => {
        const applyFallback = () => {
            const mat = new THREE.MeshStandardMaterial({ color: '#c8a830', metalness: 0.9, roughness: 0.1, envMapIntensity: 2.2 });
            scene.traverse(child => { if (child.isMesh) child.material = mat; });
            setTimeout(() => onMounted?.(), 80);
        };
        ktx2Loader.load('/images/medalRio2026Big.ktx2', (t) => {
            t.flipY = false;
            t.colorSpace = THREE.SRGBColorSpace;
            setTexture(t);
        }, undefined, applyFallback);
    }, []);

    useEffect(() => {
        if (!texture) return;
        const mat = new THREE.MeshStandardMaterial({
            map: texture, metalness: 0.88, roughness: 0.12, envMapIntensity: 2.2,
        });
        scene.traverse(child => { if (child.isMesh) child.material = mat; });
        const t = setTimeout(() => onMounted?.(), 80);
        return () => clearTimeout(t);
    }, [scene, texture, onMounted]);

    return <primitive ref={groupRef} object={scene} scale={0} position={[0, -3, 0]} />;
}

// ── Sparkles ──────────────────────────────────────────────────────────────────
const SPARKLE_COUNT = 26;

const SPARKLE_DATA = Array.from({ length: SPARKLE_COUNT }, () => ({
    tilt:    (Math.random() - 0.5) * Math.PI * 0.55,
    maxLife: 1.0 + Math.random() * 2.0,
}));

function _spawnParticle(maxLife) {
    const angle = Math.random() * Math.PI * 2;
    const speed = 0.12 + Math.random() * 0.32;
    const r     = 0.5 + Math.random() * 2.8;
    return {
        x: Math.cos(angle) * r, y: 0.0 + Math.random() * 3.8, z: Math.sin(angle) * r,
        vx: (Math.random() - 0.5) * speed, vy: 0.02 + Math.random() * 0.18, vz: (Math.random() - 0.5) * speed,
        life: maxLife, maxLife,
    };
}

// ── 3D сцена ───────────────────────────────────────────────────────────────────
const _camTarget  = new THREE.Vector3();
// Float32Arrays инициализированы нулями → (0,0,0) с AdditiveBlending = невидим
const _posArr     = new Float32Array(SPARKLE_COUNT * 3);
const _colorArr   = new Float32Array(SPARKLE_COUNT * 3);

function MedalScene({ onDone, orbitRef, visible }) {
    const medalRef       = useRef();
    const sparkleGeoRef  = useRef();
    const sparkleState   = useRef(SPARKLE_DATA.map(d => _spawnParticle(d.maxLife)));
    const sparkleOpacity = useRef(0);
    const anim           = useRef({ phase: 'rising', t: 0, settleStartTargetY: 0 });
    const firedRef       = useRef(false);
    const medalReady     = useRef(false);

    useEffect(() => {
        if (!visible) return;
        firedRef.current       = false;
        sparkleOpacity.current = 0;
        anim.current           = { phase: 'rising', t: 0, settleStartTargetY: 0 };
        sparkleState.current   = SPARKLE_DATA.map(d => _spawnParticle(d.maxLife));
        const gr = medalRef.current;
        if (gr) {
            // Медаль уже в DOM — сбрасываем позицию и сразу разрешаем анимацию
            gr.position.set(0, -3, 0);
            gr.rotation.set(-70 * Math.PI / 180, 0, 0);
            gr.scale.setScalar(1.0);
            medalReady.current = true;
        } else {
            // Первый монтаж — ждём колбэк из MedalMesh
            medalReady.current = false;
        }
        if (orbitRef?.current) {
            orbitRef.current.target.set(0, 0, 0);
            orbitRef.current.update();
        }
    }, [visible]);

    const MEDAL_ROT_X = -70 * Math.PI / 180;
    const RISE_DUR    = 2.5;

    const glowTexture = useMemo(() => {
        const W = 32, H = 64;
        const c = document.createElement('canvas');
        c.width = W; c.height = H;
        const ctx = c.getContext('2d');
        ctx.save();
        ctx.translate(W / 2, H / 2);
        ctx.scale(1, H / W);
        const g = ctx.createRadialGradient(0, 0, 0, 0, 0, W / 2);
        g.addColorStop(0.00, 'rgba(255, 230, 120, 1.0)');
        g.addColorStop(0.18, 'rgba(255, 130,  10, 1.0)');
        g.addColorStop(0.45, 'rgba(220,  60,   0, 0.55)');
        g.addColorStop(0.75, 'rgba(160,  30,   0, 0.18)');
        g.addColorStop(1.00, 'rgba(  0,   0,   0, 0.0)');
        ctx.fillStyle = g;
        ctx.beginPath(); ctx.arc(0, 0, W / 2, 0, Math.PI * 2); ctx.fill();
        ctx.restore();
        return new THREE.CanvasTexture(c);
    }, []);

    const handleMedalMounted = useCallback(() => {
        const gr = medalRef.current;
        if (gr) {
            gr.position.set(0, -3, 0);
            gr.rotation.x = MEDAL_ROT_X;
            gr.scale.setScalar(1.0);
        }
        medalReady.current = true;
    }, []);

    useFrame((_, delta) => {
        const a    = anim.current;
        const ctrl = orbitRef?.current;
        if (!medalReady.current) return;
        a.t += delta;
        let ctrlDirty = false;

        if (a.phase === 'rising') {
            const p  = Math.min(a.t / RISE_DUR, 1);
            const em = 1 - Math.pow(1 - p, 3);
            const g  = medalRef.current;
            if (g) {
                g.position.y = -3 + em * 4;
                g.rotation.x = MEDAL_ROT_X * (1 - em);
                g.rotation.y = 2 * Math.PI * em;
                if (ctrl) {
                    _camTarget.set(g.position.x, g.position.y, g.position.z);
                    ctrl.target.lerp(_camTarget, delta * 1.5);
                    ctrlDirty = true;
                }
            }
            sparkleOpacity.current = Math.min(sparkleOpacity.current + delta * 0.8, 1);
            _animateSparkles(delta);
            if (p >= 1) {
                a.phase = 'settle';
                a.t = 0;
                a.settleStartTargetY = ctrl?.target.y ?? 1;
                if (!firedRef.current) { firedRef.current = true; onDone?.(); }
            }
        }

        if (a.phase === 'settle') {
            const SETTLE_DUR = 0.9;
            const p  = Math.min(a.t / SETTLE_DUR, 1);
            const em = 1 - Math.pow(1 - p, 3);
            const g  = medalRef.current;
            if (g) g.position.y = 1 - em;
            if (ctrl) {
                ctrl.target.y = a.settleStartTargetY * (1 - em);
                ctrlDirty = true;
            }
            _animateSparkles(delta);
            if (p >= 1) {
                if (g) g.position.y = 0;
                if (ctrl) ctrl.target.y = 0;
                a.phase = 'done';
            }
        }

        if (a.phase === 'done') {
            const g = medalRef.current;
            if (g) g.rotation.y += 0.02 * delta;
            _animateSparkles(delta);
        }

        // Один вызов update() на кадр вместо трёх
        if (ctrlDirty && ctrl) ctrl.update();

        function _animateSparkles(dt) {
            const geo = sparkleGeoRef.current;
            if (!geo) return;
            const sop = sparkleOpacity.current;
            const st  = sparkleState.current;
            for (let i = 0; i < SPARKLE_COUNT; i++) {
                const s = st[i];
                s.life -= dt;
                if (s.life <= 0) { st[i] = _spawnParticle(SPARKLE_DATA[i].maxLife); continue; }
                s.x += s.vx * dt; s.y += s.vy * dt; s.z += s.vz * dt;
                s.vx += (Math.random() - 0.5) * 0.3  * dt;
                s.vy += (Math.random() - 0.5) * 0.15 * dt;
                s.vz += (Math.random() - 0.5) * 0.3  * dt;
                _posArr[i * 3]     = s.x;
                _posArr[i * 3 + 1] = s.y;
                _posArr[i * 3 + 2] = s.z;
                const op = sop * Math.sin((1 - s.life / s.maxLife) * Math.PI);
                _colorArr[i * 3]     = op;
                _colorArr[i * 3 + 1] = op;
                _colorArr[i * 3 + 2] = op;
            }
            geo.attributes.position.needsUpdate = true;
            geo.attributes.color.needsUpdate    = true;
        }
    });

    return (
        <>
            <Suspense fallback={null}>
                <MedalMesh groupRef={medalRef} onMounted={handleMedalMounted} />
            </Suspense>

            <points>
                <bufferGeometry ref={sparkleGeoRef}>
                    <bufferAttribute attach="attributes-position" args={[_posArr,   3]} />
                    <bufferAttribute attach="attributes-color"    args={[_colorArr, 3]} />
                </bufferGeometry>
                <pointsMaterial
                    map={glowTexture} size={0.1} sizeAttenuation
                    vertexColors transparent
                    blending={THREE.AdditiveBlending} depthWrite={false}
                />
            </points>
        </>
    );
}

// ── Главный компонент ──────────────────────────────────────────────────────────
export default function MedalReveal({ onClose, visible }) {
    const t = useT();
    const [ready, setReady] = useState(false);
    const [flash, setFlash] = useState(false);
    const orbitRef = useRef();
    const mvpSettings = useGameStore(s => s.mvpSettings);
    const mvpLink   = mvpSettings?.mvp_link ?? null;
    const mvpActive = !!mvpSettings?.is_active;

    useEffect(() => {
        if (!visible) {
            setReady(false);
            setFlash(false);
            return;
        }
        SoundManager.play('highscore');
        setFlash(true);
        const tFlash = setTimeout(() => setFlash(false), 480);
        return () => clearTimeout(tFlash);
    }, [visible]);

    const handleDone = useCallback(() => setReady(true), []);

    return (
        <div style={{
            display: visible ? 'block' : 'none',
            pointerEvents: visible ? 'auto' : 'none',
            position: 'absolute', inset: 0, zIndex: 3000,
            fontFamily: F_UI,
        }}>
            {visible && <div style={{
                position: 'absolute', inset: 0,
                background: 'rgba(0,0,0,0.15)',
                backdropFilter: 'blur(6px)',
                WebkitBackdropFilter: 'blur(6px)',
                animation: 'medalRevealIn 0.4s ease-out both',
                pointerEvents: 'none',
                // Вынос в отдельный GPU-слой до начала blur-композиции
                willChange: 'transform',
                transform: 'translateZ(0)',
            }} />}

            <Canvas
                camera={{ position: [0, 0.5, 2.2], fov: 48 }}
                gl={{ antialias: true, alpha: true }}
                dpr={[1, 1.5]}
                frameloop={visible ? 'always' : 'never'}
                style={{ position: 'absolute', inset: 0, background: 'transparent' }}
            >
                <KTX2Init />
                <EnvBoundary>
                    <Environment
                        files="/images/qwantani_mid_morning_puresky_1k.hdr"
                        backgroundBlurriness={ 0.1 }
                        backgroundIntensity={ 1.5 }
                    />
                </EnvBoundary>
                <ambientLight intensity={13.25} />
                <directionalLight position={[3, 6, 4]}   intensity={7.2} color="#ffe8a0" />
                <directionalLight position={[-3, 4, -5]} intensity={4.6} color="#a0c8ff" />
                <pointLight position={[0, 1, 2]} intensity={4.0} color="#ffcc44" />

                <MedalScene onDone={handleDone} orbitRef={orbitRef} visible={visible} />

                <OrbitControls ref={orbitRef}
                    enablePan={true}
                    enableZoom={true} zoomSpeed={1.2}
                    minDistance={0.4} maxDistance={4}
                    autoRotate autoRotateSpeed={0.3}
                    minPolarAngle={Math.PI * 0.1}
                    maxPolarAngle={Math.PI * 0.82}
                />
            </Canvas>

            {flash && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 2150,
                    background: 'white', pointerEvents: 'none',
                    animation: 'flashBurst 0.5s ease-out forwards',
                }} />
            )}

            {/* Конфетти: 0 React-state, 0 DOM-узлов, RAF + Canvas2D */}
            <ConfettiCanvas active={visible} />

            {ready && (
                <div style={{
                    position: 'absolute', top: '5%', left: 0, right: 0,
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '6px',
                    pointerEvents: 'none',
                    animation: 'medalRevealIn 0.5s ease-out both',
                }}>
                    <div style={{ fontFamily: F_UI, fontSize: '9px', letterSpacing: '4px', color: 'rgba(255,204,0,0.5)' }}>
                        {t.medalUnlocked}
                    </div>
                    <div style={{
                        fontFamily: F_TITLE,
                        fontSize: 'clamp(22px,7vw,32px)', fontWeight: 900,
                        color: '#ffcc00', textShadow: `0 4px 0 ${C_CARD_SHADOW}`,
                    }}>
                        MVP RIO 2026
                    </div>
                </div>
            )}

            <div style={{
                position: 'absolute',
                bottom: 'max(env(safe-area-inset-bottom, 0px) + 70px, 90px)',
                left: 0, right: 0,
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '12px',
                opacity: ready ? 1 : 0,
                transition: 'opacity 0.5s ease-out',
                pointerEvents: ready ? 'auto' : 'none',
                zIndex: 2120,
            }}>
                <div style={{ fontFamily: F_UI, fontSize: '10px', letterSpacing: '2px', color: 'rgba(255,255,255,0.28)', pointerEvents: 'none' }}>
                    {t.dragToRotate}
                </div>
                <GameButton
                    onPointerDown={onClose}
                    bg={OG_GRAD}
                    color="#fff"
                    textShadow={`0 2px 0 ${C_CARD_SHADOW}`}
                    shadowColor={C_BTN_SHADOW}
                    height={52}
                    wrapperStyle={{ width: 'min(90%, 260px)' }}
                    style={{ touchAction: 'manipulation' }}
                >
                    <span style={{ fontFamily: F_TITLE, fontSize: 'clamp(16px,4.5vw,18px)', fontWeight: 700, letterSpacing: '1px', textShadow: `0 2px 0 ${C_CARD_SHADOW}`}}>
                        {t.chooseUpgrade}
                    </span>
                </GameButton>
                {mvpActive && mvpLink && (
                    <GameButton
                        onPointerDown={(e) => { e.stopPropagation(); }}
                        onClick={() => window.open(mvpLink, '_blank', 'noopener,noreferrer')}
                        bg="rgba(255,255,255,0.08)"
                        color="#ffcc00"
                        shadowColor="rgba(255,204,0,0.25)"
                        textShadow={`0 2px 0 ${C_CARD_SHADOW}`}
                        height={44}
                        wrapperStyle={{ width: 'min(90%, 260px)' }}
                        style={{ touchAction: 'manipulation' }}
                    >
                        <span style={{ fontFamily: F_TITLE, fontSize: 'clamp(14px,4vw,16px)', fontWeight: 700, letterSpacing: '1px', textShadow: `0 2px 0 ${C_CARD_SHADOW}` }}>
                            {t.btnWatch}
                        </span>
                    </GameButton>
                )}
            </div>

            <style>{`
                @keyframes medalRevealIn {
                    0%   { opacity: 0; transform: scale(1.06); }
                    100% { opacity: 1; transform: scale(1); }
                }
                @keyframes flashBurst {
                    0%   { opacity: 0.85; }
                    100% { opacity: 0; }
                }
            `}</style>
        </div>
    );
}
