import { API_BASE_URL, DEVICE_ID, PLATFORM, APP_VERSION } from './constants';

// ── Helpers ───────────────────────────────────────────────────────────────────

function authHeaders(jwt) {
    return {
        'Content-Type':  'application/json',
        'Authorization': `Bearer ${jwt}`,
    };
}

async function apiFetch(method, path, body, headers) {
    const res = await fetch(`${API_BASE_URL}${path}`, {
        method,
        headers,
        ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
    });
    if (!res.ok) {
        const err = new Error(`HTTP ${res.status}`);
        err.status = res.status;
        try { err.data = await res.json(); } catch (_) { /* ignore */ }
        throw err;
    }
    return res.json();
}

// ── Auth ──────────────────────────────────────────────────────────────────────

export async function apiRegister(email, password) {
    return apiFetch('POST', '/auth/register', {
        email,
        password,
        password_confirmation: password,
        device_id: DEVICE_ID,
        platform: PLATFORM,
        app_version: APP_VERSION,
    }, { 'Content-Type': 'application/json' });
}

export async function apiLogin(email, password) {
    return apiFetch('POST', '/auth/login', {
        email,
        password,
        device_id: DEVICE_ID,
        platform: PLATFORM,
        app_version: APP_VERSION,
    }, { 'Content-Type': 'application/json' });
}

// Auth with email+password: try register → fallback to login only if email is taken
export async function apiAuthWithEmail(email, password) {
    try {
        const data = await apiRegister(email, password);
        return { token: data.data?.token ?? data.token, email, isNew: true };
    } catch (e) {
        if (e.status === 422) {
            const errors = e.data?.errors ?? {};
            const emailErrors = errors.email ?? [];
            const emailTaken = emailErrors.some(msg =>
                msg.toLowerCase().includes('taken') || msg.toLowerCase().includes('already')
            );
            if (emailTaken) {
                // Email exists — try login with same password
                const data = await apiLogin(email, password);
                return { token: data.data?.token ?? data.token, email, isNew: false };
            }
            // Other validation error — extract first message and re-throw
            const firstMsg = Object.values(errors)?.[0]?.[0] ?? `HTTP 422`;
            const err = new Error(firstMsg);
            err.status = 422;
            throw err;
        }
        throw e;
    }
}

export async function apiLogout(jwt) {
    return apiFetch('POST', '/auth/logout', undefined, authHeaders(jwt));
}

export async function apiLogoutAll(jwt) {
    return apiFetch('POST', '/auth/logout-all-devices', undefined, authHeaders(jwt));
}

