// ── Leaderboard ───────────────────────────────────────────────────────────────

export async function apiGetLeaderboard(jwt) {
    const headers = { 'Content-Type': 'application/json' };
    if (jwt) headers['Authorization'] = `Bearer ${jwt}`;
    return apiFetch('GET', '/game/leaderboard', undefined, headers);
}

