import { useEffect } from 'react';
import { useThree } from '@react-three/fiber';
import ktx2Loader from './View/ktx2Loader';
import { loadSharedTextures } from './View/sharedMaterial';
import { loadCausticsTexture } from './View/WaterBottomLayers';
import GlobalLoop from "./Logic/GlobalLoop";
import SmartCamera from "./Scene/SmartCamera";
import BatchedWorldView from "./View/BatchedWorldView";
import CoinMedalBatchView from "./View/CoinMedalBatchView";
import WaterEffectsView from "./View/WaterEffectsView";
import Map from "./Map/Map";
import StartLocation from "./Map/StartLocation";
import StartFloor from "./Map/StartFloor";
import StartWater from "./View/StartWater";
import StartWalls from "./View/StartWalls";
import StartDivider from "./View/StartDivider";
import Player from "./Player/Player";
import Lights from "./Scene/Lights";
import PlayerController from "./Player/PlayerController";
import DangerController from "./Player/DangerController";
import WaterSplash from "./Effects/WaterSplash";
import DustPuff from "./Effects/DustPuff";

function KTX2Init() {
    const { gl } = useThree();
    useEffect(() => {
        ktx2Loader.detectSupport(gl);
        loadSharedTextures();
        loadCausticsTexture();
    }, [gl]);
    return null;
}

export default function Scene() {
    return (
        <>
            <KTX2Init />
            <SmartCamera />
            <Lights />
            <GlobalLoop />
            <BatchedWorldView />
<CoinMedalBatchView />
            <WaterEffectsView />

            <StartLocation />
            <StartFloor />
            <StartWater />
            <StartWalls />
            <StartDivider />
            <Map />
            <PlayerController />
            <DangerController />
            <Player />
            <WaterSplash />
            <DustPuff />
        </>
    );
}