import { useGLTF } from '@react-three/drei';
import { useEffect, useState } from 'react';
import * as THREE from 'three';
import { sharedAtlasMaterial, sharedShadowMaterial } from './sharedMaterial';

const WALL_VARIANTS = ['wallA', 'wallB', 'wallC', 'wallD', 'wallE'];
const WALL_XS = [-5.75, 5.75];
// [z, y] пары
const WALL_ROWS = [
    [-6,  0],
    [-7,  0],
    [-8,  -1.8],
    [-9,  -1.8],
    [-10, -1.8],
];
const COUNT = WALL_ROWS.length * WALL_XS.length;

const temp = new THREE.Object3D();

const pickVariant = (x, z) =>
    WALL_VARIANTS[Math.abs(Math.round(x * 7 + z * 13)) % 5];

export default function StartWalls() {
    const { nodes: wallNodes }   = useGLTF('/models/wallwindow.glb');
    const { nodes: shadowNodes } = useGLTF('/models/shadow.glb');
    const [batch,  setBatch]  = useState(null);
    const [shadow, setShadow] = useState(null);

    useEffect(() => {
        const keys = WALL_VARIANTS;
        const allLoaded = keys.every(k => wallNodes[k]?.geometry);
        if (!allLoaded) return;

        // ── Стены ────────────────────────────────────────────────────────────
        let totalVerts = 0, totalIdx = 0;
        keys.forEach(k => {
            const geo = wallNodes[k].geometry;
            totalVerts += geo.attributes.position.count;
            totalIdx   += geo.index ? geo.index.count : geo.attributes.position.count;
        });

        const b = new THREE.BatchedMesh(
            keys.length * COUNT, totalVerts, totalIdx, sharedAtlasMaterial
        );
        b.frustumCulled          = false;
        b.perObjectFrustumCulled = false;

        const geoIds = {};
        keys.forEach(k => { geoIds[k] = b.addGeometry(wallNodes[k].geometry); });

        for (const [z, y] of WALL_ROWS) {
            for (const x of WALL_XS) {
                const key = pickVariant(x, z);
                const id  = b.addInstance(geoIds[key]);
                temp.position.set(x, y, z);
                temp.rotation.set(0, 0, 0);
                temp.scale.set(1, 1, 1);
                temp.updateMatrix();
                b.setMatrixAt(id, temp.matrix);
                b.setVisibleAt(id, true);
            }
        }

        setBatch(b);

        // ── Тени стен ────────────────────────────────────────────────────────
        const shadowGeo = shadowNodes['shadow_wall']?.geometry;
        if (!shadowGeo) return () => { b.dispose(); };

        const sv = shadowGeo.attributes.position.count;
        const si = shadowGeo.index ? shadowGeo.index.count : sv;
        const bs = new THREE.BatchedMesh(COUNT, sv, si, sharedShadowMaterial);
        bs.frustumCulled          = false;
        bs.perObjectFrustumCulled = false;

        const shadowGeoId = bs.addGeometry(shadowGeo);
        for (const [z, y] of WALL_ROWS) {
            for (const x of WALL_XS) {
                const id = bs.addInstance(shadowGeoId);
                temp.position.set(x, y + 0.05, z);
                temp.rotation.set(0, 0, 0);
                temp.scale.set(1, 1, 1);
                temp.updateMatrix();
                bs.setMatrixAt(id, temp.matrix);
                bs.setVisibleAt(id, true);
            }
        }

        setShadow(bs);
        return () => { b.dispose(); bs.dispose(); };
    }, [wallNodes, shadowNodes]);

    return (
        <>
            {batch  && <primitive object={batch}  />}
            {shadow && <primitive object={shadow} />}
        </>
    );
}
