import { useGLTF } from '@react-three/drei';
import { useFrame } from '@react-three/fiber';
import { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { useGameStore } from '../Logic/store';
import { sharedAtlasMaterial, sharedShadowMaterial, sharedLogoMaterial, sharedGrenadeMaterial, transpPointsUniform, DISSOLVE_SLOTS } from './sharedMaterial';
import { useWorld } from '../Logic/GameWorldContext';
import {
    POOL_OBSTACLE_BOX, POOL_OBSTACLE_PALM, POOL_OBSTACLE_PILLAR, POOL_OBSTACLE_STATUE, POOL_OBSTACLE_TOWER,
    POOL_WALL, POOL_WOODEN, POOL_BOAT, POOL_LILY,
    POOL_GRENADE_HE, POOL_GRENADE_FLASH, POOL_GRENADE_MOLOTOV,
    POOL_WATERSIDE,
    POOL_SHADOW_PROP, POOL_SHADOW_WALL, POOL_SHADOW_LOG, POOL_SHADOW_LILY,
    POOL_SHADOW_GRENADE, POOL_SHADOW_COIN, POOL_SHADOW_MEDAL_PART,
    WATER_Y,
    WATER_BOTTOM_OFFSET,
    SUN_OFFSET,
} from '../Logic/constants';

const SHADOW_Y_GROUND = 0.025;
const SHADOW_Y_WATER  = WATER_Y - WATER_BOTTOM_OFFSET + 0.01;

const temp = new THREE.Object3D();

const WALL_VARIANTS = ['wallA', 'wallB', 'wallC', 'wallD', 'wallE'];
const WALL_POOL_PER = Math.ceil(POOL_WALL / 5);

// ── Atlas batch — всё с sharedAtlasMaterial ───────────────────────────────────
const POOL_ATLAS = {
    obstacle_box:    POOL_OBSTACLE_BOX,
    obstacle_palm:   POOL_OBSTACLE_PALM,
    obstacle_pillar: POOL_OBSTACLE_PILLAR,
    obstacle_statue: POOL_OBSTACLE_STATUE,
    obstacle_tower:  POOL_OBSTACLE_TOWER,
    wooden:          POOL_WOODEN,
    boat:            POOL_BOAT,
    lily:            POOL_LILY,
    waterside:       POOL_WATERSIDE,
};

// ── Grenade batch — блестящий металлический материал ──────────────────────────
const POOL_GRENADE_BATCH = {
    grenade_HE:      POOL_GRENADE_HE,
    grenade_Flash:   POOL_GRENADE_FLASH,
    grenade_Molotov: POOL_GRENADE_MOLOTOV,
};

// ── Main batch — стены ────────────────────────────────────────────────────────
const POOL_MAIN = {
    wallA: WALL_POOL_PER,
    wallB: WALL_POOL_PER,
    wallC: WALL_POOL_PER,
    wallD: WALL_POOL_PER,
    wallE: WALL_POOL_PER,
};

const TOTAL_ATLAS   = Object.values(POOL_ATLAS).reduce((s, n) => s + n, 0);
const TOTAL_MAIN    = Object.values(POOL_MAIN).reduce((s, n) => s + n, 0);
const TOTAL_GRENADE = Object.values(POOL_GRENADE_BATCH).reduce((s, n) => s + n, 0);

const PROP_TYPE_TO_KEY = {
    obstacle_box:    'obstacle_box',
    obstacle_palm:   'obstacle_palm',
    obstacle_pillar: 'obstacle_pillar',
    obstacle_statue: 'obstacle_statue',
    obstacle_tower:  'obstacle_tower',
};

const SHADOW_GEO_KEYS = ['shadow_box', 'shadow_palm', 'shadow_pillar', 'shadow_statue', 'shadow_tower', 'shadow_boat', 'shadow_lilly', 'shadow_wooden', 'shadow_wall', 'shadow_he', 'shadow_flashbang', 'shadow_molotov', 'shadow_coin', 'shadow_part1', 'shadow_part2', 'shadow_part3', 'shadow_part4', 'shadow_part5'];

// ── Logo graffiti batch — shadow material, 2% spawn rate ──────────────────────
const POOL_LOGO_BATCH = {
    logo_box:     6,   // 20 max props × 15% ≈ 3
    logo_pillar:  6,
    logo_statue:  6,
    logo_tower:   6,
    logo_tower2:  6,
    logo_wallTop: 12,  // 36 eligible walls × 25% ≈ 9
    logo_wallBot: 12,
};
const TOTAL_LOGO = Object.values(POOL_LOGO_BATCH).reduce((s, n) => s + n, 0);

const PROP_TO_LOGOS = {
    obstacle_box:    ['logo_box'],
    obstacle_pillar: ['logo_pillar'],
    obstacle_statue: ['logo_statue'],
    obstacle_tower:  ['logo_tower', 'logo_tower2'],
};

const _logoCounts = { logo_box: 0, logo_pillar: 0, logo_statue: 0, logo_tower: 0, logo_tower2: 0, logo_wallTop: 0, logo_wallBot: 0 };
const _logoHash = (x, z, salt) => Math.abs(Math.sin(x * 73.137 + z * 91.713 + salt * 317)) % 1;

const PROP_TO_SHADOW = {
    obstacle_box:    'shadow_box',
    obstacle_palm:   'shadow_palm',
    obstacle_pillar: 'shadow_pillar',
    obstacle_statue: 'shadow_statue',
    obstacle_tower:  'shadow_tower',
};

const SHADOW_POOL = {
    shadow_box:      POOL_SHADOW_PROP,
    shadow_palm:     POOL_SHADOW_PROP,
    shadow_pillar:   POOL_SHADOW_PROP,
    shadow_statue:   POOL_SHADOW_PROP,
    shadow_tower:    POOL_SHADOW_PROP,
    shadow_boat:     POOL_SHADOW_LOG,
    shadow_lilly:    POOL_SHADOW_LILY,
    shadow_wooden:   POOL_SHADOW_LOG,
    shadow_wall:     POOL_SHADOW_WALL,
    shadow_he:       POOL_SHADOW_GRENADE,
    shadow_flashbang: POOL_SHADOW_GRENADE,
    shadow_molotov:  POOL_SHADOW_GRENADE,
    shadow_coin:     POOL_SHADOW_COIN,
    shadow_part1:    POOL_SHADOW_MEDAL_PART,
    shadow_part2:    POOL_SHADOW_MEDAL_PART,
    shadow_part3:    POOL_SHADOW_MEDAL_PART,
    shadow_part4:    POOL_SHADOW_MEDAL_PART,
    shadow_part5:    POOL_SHADOW_MEDAL_PART,
};

const TOTAL_SHADOW = Object.values(SHADOW_POOL).reduce((s, n) => s + n, 0);

const _grenadeLight = new THREE.Color(1, 1, 1);
const _grenadeDark  = new THREE.Color(0.5, 0.5, 0.5);
const _grenadeColor = new THREE.Color();


// ── propsByZ cache — rebuilt only when props list changes ─────────────────────
// Exported so Player.js can reuse the same cache (avoids O(n) scan per frame)
export const _propsByZ = new Map();

const _propCounts   = { obstacle_box: 0, obstacle_palm: 0, obstacle_pillar: 0, obstacle_statue: 0, obstacle_tower: 0 };
const _wallCounts   = { wallA: 0, wallB: 0, wallC: 0, wallD: 0, wallE: 0 };
const _logCounts    = { wooden: 0, boat: 0 };
const _grenCounts   = { HE: 0, Flash: 0, Molotov: 0 };
const _shadowCounts = { shadow_box: 0, shadow_palm: 0, shadow_pillar: 0, shadow_statue: 0, shadow_tower: 0, shadow_boat: 0, shadow_lilly: 0, shadow_wooden: 0, shadow_wall: 0, shadow_he: 0, shadow_flashbang: 0, shadow_molotov: 0, shadow_coin: 0, shadow_part1: 0, shadow_part2: 0, shadow_part3: 0, shadow_part4: 0, shadow_part5: 0 };

// Dirty tracking для статических объектов (пропсы, стены, waterside)
let _prevPropsLen    = -1;
let _prevPropsKeyZ   = 0;
let _prevPropsLastZ  = 0;   // last-element z — ловит случай, когда кол-во пропсов не изменилось,
                             // но окно сдвинулось (старые ряды удалены, новые добавлены с тем же счётом)
let _prevWindowsLen  = -1;
let _prevWindowsKeyZ = 0;
let _prevWindowsLastZ = 0;  // аналогично для стен
let _prevWatersLen   = -1;
let _prevWatersFirstZ = 0;

export default function BatchedWorldView() {
    const world = useWorld();

    const { nodes: obsNodes    } = useGLTF('/models/obstacle.glb');
    const { nodes: wallNodes   } = useGLTF('/models/wallwindow.glb');
    const { nodes: woodNodes   } = useGLTF('/models/wooden.glb');
    const { nodes: boatNodes   } = useGLTF('/models/boat.glb');
    const { nodes: lilyNodes   } = useGLTF('/models/lilly.glb');
    const { nodes: grenNodes   } = useGLTF('/models/grenade.glb');
    const { nodes: sideNodes   } = useGLTF('/models/waterside.glb');
    const { nodes: shadowNodes } = useGLTF('/models/shadow.glb');
    const { nodes: logoNodes   } = useGLTF('/models/logo.glb');

    const [batches, setBatches] = useState(null);
    const poolsRef   = useRef({});
    const prevCounts = useRef({});

    useEffect(() => {
        const geoMapAtlas = {
            obstacle_box:    obsNodes.obstacle_box?.geometry,
            obstacle_palm:   obsNodes.obstacle_palm?.geometry,
            obstacle_pillar: obsNodes.obstacle_pillar?.geometry,
            obstacle_statue: obsNodes.obstacle_statue?.geometry,
            obstacle_tower:  obsNodes.obstacle_tower?.geometry,
            wooden:          woodNodes.modelsanubismarketwooden_walkwayvmdl_cwooden_walkway_bg_mybody_lod0002?.geometry,
            boat:            boatNodes.Model_Boat002005?.geometry,
            lily:            lilyNodes.lily_001?.geometry,
            waterside:       Object.values(sideNodes).find(n => n.isMesh)?.geometry,
        };

        const geoMapGrenade = {
            grenade_HE:      grenNodes.weaponsmodelsgrenadehegrenadeweapon_hegrenadevmdl_cbody001?.geometry,
            grenade_Flash:   grenNodes.weaponsmodelsgrenadeflashbangweapon_flashbangvmdl_cbody002?.geometry,
            grenade_Molotov: grenNodes.weaponsmodelsgrenademolotovweapon_molotovvmdl_cbody007?.geometry,
        };

        const geoMapMain = {
            wallA: wallNodes.wallA?.geometry,
            wallB: wallNodes.wallB?.geometry,
            wallC: wallNodes.wallC?.geometry,
            wallD: wallNodes.wallD?.geometry,
            wallE: wallNodes.wallE?.geometry,
        };

        const geoMapShadow = {};
        for (const k of SHADOW_GEO_KEYS) {
            const node = shadowNodes[k];
            if (!node?.geometry) return;
            // No clone needed — shadow geos have no uv1/uv2/uv3, so stripExtras is a no-op
            // and BatchedMesh.addGeometry reads but does not mutate the source geometry.
            geoMapShadow[k] = node.geometry;
        }

        if (Object.values(geoMapAtlas).some(g => !g)) return;
        if (Object.values(geoMapMain).some(g => !g)) return;
        if (Object.values(geoMapGrenade).some(g => !g)) return;

        const calcSize = (geoMap) => {
            let verts = 0, idx = 0;
            Object.values(geoMap).forEach(geo => {
                verts += geo.attributes.position.count;
                idx   += geo.index ? geo.index.count : geo.attributes.position.count;
            });
            return { verts, idx };
        };

        const atlasSize = calcSize(geoMapAtlas);
        const mainSize  = calcSize(geoMapMain);

        const bAtlas = new THREE.BatchedMesh(TOTAL_ATLAS, atlasSize.verts, atlasSize.idx, sharedAtlasMaterial);        bAtlas.frustumCulled          = false;
        bAtlas.perObjectFrustumCulled = false;

        const bMain = new THREE.BatchedMesh(TOTAL_MAIN, mainSize.verts, mainSize.idx, sharedAtlasMaterial);
        bMain.frustumCulled          = false;
        bMain.perObjectFrustumCulled = false;

        const pools = {};

        const stripExtras = (geo) => {
            ['uv1', 'uv2', 'uv3'].forEach(attr => { if (geo.attributes[attr]) geo.deleteAttribute(attr); });
            return geo;
        };

        const addToBatch = (b, poolDef, geoMap) => {
            Object.entries(geoMap).forEach(([key, geo]) => {
                const geoId = b.addGeometry(stripExtras(geo));
                const ids   = [];
                for (let i = 0; i < poolDef[key]; i++) {
                    const id = b.addInstance(geoId);
                    b.setVisibleAt(id, false);
                    ids.push(id);
                }
                pools[key] = { b, ids };
            });
        };

        addToBatch(bAtlas, POOL_ATLAS, geoMapAtlas);

        // Стены — без stripExtras, чтобы сохранить все UV-каналы для atlas-текстуры
        Object.entries(geoMapMain).forEach(([key, geo]) => {
            const geoId = bMain.addGeometry(geo);
            const ids   = [];
            for (let i = 0; i < POOL_MAIN[key]; i++) {
                const id = bMain.addInstance(geoId);
                bMain.setVisibleAt(id, false);
                ids.push(id);
            }
            pools[key] = { b: bMain, ids };
        });

        // ── Grenade BatchedMesh ───────────────────────────────────────────────
        const grenadeSize = calcSize(geoMapGrenade);
        const bGrenade = new THREE.BatchedMesh(TOTAL_GRENADE, grenadeSize.verts, grenadeSize.idx, sharedGrenadeMaterial);
        bGrenade.frustumCulled          = false;
        bGrenade.perObjectFrustumCulled = false;
        addToBatch(bGrenade, POOL_GRENADE_BATCH, geoMapGrenade);

        // ── Shadow BatchedMesh ────────────────────────────────────────────────
        const shadowSize = calcSize(geoMapShadow);
        const bShadow = new THREE.BatchedMesh(TOTAL_SHADOW, shadowSize.verts, shadowSize.idx, sharedShadowMaterial);
        bShadow.frustumCulled          = false;
        bShadow.perObjectFrustumCulled = false;
        bShadow.renderOrder            = 1;
        addToBatch(bShadow, SHADOW_POOL, geoMapShadow);

        poolsRef.current  = pools;
        // ── Logo graffiti BatchedMesh ─────────────────────────────────────────
        const geoMapLogo = {
            logo_box:     logoNodes.logoGraf_Box?.geometry,
            logo_pillar:  logoNodes.logoGraf_Pillar?.geometry,
            logo_statue:  logoNodes.logoGraf_Statue?.geometry,
            logo_tower:   logoNodes.logoGraf_Tower?.geometry,
            logo_tower2:  logoNodes.logoGraf_Tower2?.geometry,
            logo_wallTop: logoNodes.logoGraf_WallTop?.geometry,
            logo_wallBot: logoNodes.logoGraf_WallBot?.geometry,
        };
        if (Object.values(geoMapLogo).some(g => !g)) return;
        const logoSize = calcSize(geoMapLogo);
        const bLogo = new THREE.BatchedMesh(TOTAL_LOGO, logoSize.verts, logoSize.idx, sharedLogoMaterial);
        bLogo.frustumCulled          = false;
        bLogo.perObjectFrustumCulled = false;
        bLogo.renderOrder            = 2;
        addToBatch(bLogo, POOL_LOGO_BATCH, geoMapLogo);

        prevCounts.current = Object.fromEntries(
            [...Object.keys(POOL_ATLAS), ...Object.keys(POOL_MAIN), ...Object.keys(POOL_GRENADE_BATCH), ...SHADOW_GEO_KEYS, ...Object.keys(POOL_LOGO_BATCH)].map(k => [k, 0])
        );
        setBatches({ atlas: bAtlas, main: bMain, grenade: bGrenade, shadow: bShadow, logo: bLogo });

        return () => {
            bAtlas.dispose(); bMain.dispose(); bGrenade.dispose(); bShadow.dispose(); bLogo.dispose();
            setBatches(null);
        };
    }, [obsNodes, wallNodes, woodNodes, boatNodes, lilyNodes, grenNodes, sideNodes, shadowNodes, logoNodes]);

    useFrame((state) => {
        if (!batches) return;
        if (useGameStore.getState().isPaused) return;
        const pools = poolsRef.current;
        const prev  = prevCounts.current;
        const time  = state.clock.elapsedTime;

        const show = (key, idx, matrix) => {
            const entry = pools[key];
            if (!entry || idx >= entry.ids.length) return;
            entry.b.setMatrixAt(entry.ids[idx], matrix);
            entry.b.setVisibleAt(entry.ids[idx], true);
        };

        const showShadow = (shadowKey, x, z, y = SHADOW_Y_GROUND) => {
            const idx = _shadowCounts[shadowKey]++;
            temp.position.set(x, y, z);
            temp.rotation.set(0, 0, 0);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            show(shadowKey, idx, temp.matrix);
        };

        const commit = (key, newCount) => {
            const entry = pools[key];
            if (!entry) return;
            const safeNew = Math.min(newCount, entry.ids.length);
            const oldCount = prev[key] ?? 0;
            for (let i = safeNew; i < oldCount; i++) entry.b.setVisibleAt(entry.ids[i], false);
            prev[key] = safeNew;
        };

        // ── Dirty-флаги для статических объектов ──────────────────────────────
        const propsLen   = world.props.length;
        const propsKeyZ  = world.props[0]?.z ?? 0;
        const propsLastZ = world.props[propsLen - 1]?.z ?? 0;
        const propsDirty = propsLen !== _prevPropsLen || propsKeyZ !== _prevPropsKeyZ || propsLastZ !== _prevPropsLastZ;

        const windowsLen   = world.windows.length ?? 0;
        const windowsKeyZ  = world.windows[0]?.z ?? 0;
        const windowsLastZ = world.windows[windowsLen - 1]?.z ?? 0;
        const windowsDirty = windowsLen !== _prevWindowsLen || windowsKeyZ !== _prevWindowsKeyZ || windowsLastZ !== _prevWindowsLastZ;

        const watersLen    = world.waters.size;
        const watersFirstZ = world.waters.size ? world.waters.values().next().value : 0;
        const watersDirty  = watersLen !== _prevWatersLen || watersFirstZ !== _prevWatersFirstZ;

        // ── Пропсы (только при изменении карты) ───────────────────────────────
        if (propsDirty) {
            _prevPropsLen   = propsLen;
            _prevPropsKeyZ  = propsKeyZ;
            _prevPropsLastZ = propsLastZ;
            _shadowCounts.shadow_box = _shadowCounts.shadow_palm = _shadowCounts.shadow_pillar =
            _shadowCounts.shadow_statue = _shadowCounts.shadow_tower = 0;
            _propCounts.obstacle_box = _propCounts.obstacle_palm = _propCounts.obstacle_pillar =
            _propCounts.obstacle_statue = _propCounts.obstacle_tower = 0;
            _logoCounts.logo_box = _logoCounts.logo_pillar = _logoCounts.logo_statue = _logoCounts.logo_tower = _logoCounts.logo_tower2 = 0;
            for (const p of world.props) {
                const key = PROP_TYPE_TO_KEY[p.type] ?? 'obstacle_pillar';
                const idx = _propCounts[key]++;
                temp.position.set(p.x, 0, p.z);
                temp.rotation.set(0, (p.id.length % 4) * (Math.PI / 2), 0);
                temp.scale.set(1, 1, 1);
                temp.updateMatrix();
                show(key, idx, temp.matrix);
                // Logo graffiti — до showShadow, чтобы temp сохранял ротацию пропса
                const logoKeys = PROP_TO_LOGOS[p.type];
                if (logoKeys) {
                    for (let li = 0; li < logoKeys.length; li++) {
                        if (_logoHash(p.x, p.z, 1 + li) < 0.075) {
                            const logoKey = logoKeys[li];
                            show(logoKey, _logoCounts[logoKey]++, temp.matrix);
                        }
                    }
                }
                showShadow(PROP_TO_SHADOW[p.type] ?? 'shadow_pillar', p.x, p.z);
            }
            commit('obstacle_box',    _propCounts.obstacle_box);
            commit('obstacle_palm',   _propCounts.obstacle_palm);
            commit('obstacle_pillar', _propCounts.obstacle_pillar);
            commit('obstacle_statue', _propCounts.obstacle_statue);
            commit('obstacle_tower',  _propCounts.obstacle_tower);
            commit('shadow_box',      _shadowCounts.shadow_box);
            commit('shadow_palm',     _shadowCounts.shadow_palm);
            commit('shadow_pillar',   _shadowCounts.shadow_pillar);
            commit('shadow_statue',   _shadowCounts.shadow_statue);
            commit('shadow_tower',    _shadowCounts.shadow_tower);
            commit('logo_box',        _logoCounts.logo_box);
            commit('logo_pillar',     _logoCounts.logo_pillar);
            commit('logo_statue',     _logoCounts.logo_statue);
            commit('logo_tower',      _logoCounts.logo_tower);
            commit('logo_tower2',     _logoCounts.logo_tower2);

            // propsByZ для гранат пересчитываем вместе с пропсами
            _propsByZ.clear();
            for (const p of world.props) {
                const rz = Math.round(p.z);
                if (!_propsByZ.has(rz)) _propsByZ.set(rz, []);
                _propsByZ.get(rz).push(p.x);
            }
        }

        // ── Стены (только при изменении карты) ────────────────────────────────
        if (windowsDirty) {
            _prevWindowsLen   = windowsLen;
            _prevWindowsKeyZ  = windowsKeyZ;
            _prevWindowsLastZ = windowsLastZ;
            _shadowCounts.shadow_wall = 0;
            _wallCounts.wallA = _wallCounts.wallB = _wallCounts.wallC = _wallCounts.wallD = _wallCounts.wallE = 0;
            _logoCounts.logo_wallTop = _logoCounts.logo_wallBot = 0;
            for (const data of world.windows) {
                const vi  = Math.abs(Math.round(data.x * 7 + data.z * 13)) % 5;
                const key = WALL_VARIANTS[vi];
                temp.position.set(data.x, 0, data.z);
                temp.rotation.set(0, 0, 0); temp.scale.set(1, 1, 1);
                temp.updateMatrix(); show(key, _wallCounts[key]++, temp.matrix);
                showShadow('shadow_wall', data.x, data.z);
                // Logo graffiti — wallB/D/E → WallTop, wallC/D/E → WallBot, 5%
                if ((vi === 1 || vi === 3 || vi === 4) && _logoHash(data.x, data.z, 2) < 0.25) {
                    show('logo_wallTop', _logoCounts.logo_wallTop++, temp.matrix);
                }
                if ((vi === 2 || vi === 3 || vi === 4) && _logoHash(data.x, data.z, 3) < 0.25) {
                    show('logo_wallBot', _logoCounts.logo_wallBot++, temp.matrix);
                }
            }
            WALL_VARIANTS.forEach(k => commit(k, _wallCounts[k]));
            commit('shadow_wall',  _shadowCounts.shadow_wall);
            commit('logo_wallTop', _logoCounts.logo_wallTop);
            commit('logo_wallBot', _logoCounts.logo_wallBot);
        }

        // ── Брёвна и лодки (анимация — каждый кадр) ───────────────────────────
        _shadowCounts.shadow_boat = _shadowCounts.shadow_wooden = 0;
        _logCounts.wooden = _logCounts.boat = 0;
        const logKeyMap = { Wooden: 'wooden', Boat: 'boat' };
        for (let i = 0; i < world.logs.length; i++) {
            const data = world.logs[i];
            const key  = logKeyMap[data.type];
            if (!key) continue;

            const yOffset = data.yOffset || 0;
            const wave    = Math.sin(time * 1.5 + i * 0.7) * 0.04;
            let shakeY = 0, shakeRotX = 0, shakeRotZ = 0;
            if (data.shakeTime) {
                if (data.shakeTime === -1) data.shakeTime = time;
                const age = time - data.shakeTime;
                if (age < 0.55) {
                    const decay = Math.exp(-age * 10), osc = Math.sin(age * 36);
                    shakeY    = osc * decay * 0.10;
                    shakeRotX = osc * decay * 0.15 * (data.shakeDir || 1);
                    shakeRotZ = Math.sin(age * 22) * decay * 0.07;
                } else { data.shakeTime = 0; }
            }
            temp.position.set(data.x, yOffset + wave + shakeY, data.z);
            temp.rotation.set((data.rotX||0) + Math.sin(time*1.5+i*0.7)*0.06 + shakeRotX, 0, (data.rotZ||0) + shakeRotZ);
            temp.scale.set(1, 1, 1.135);
            temp.updateMatrix();
            show(key, _logCounts[key]++, temp.matrix);
            showShadow(key === 'boat' ? 'shadow_boat' : 'shadow_wooden', data.x, data.z, SHADOW_Y_WATER);
        }
        commit('wooden', _logCounts.wooden);
        commit('boat',   _logCounts.boat);
        commit('shadow_boat',   _shadowCounts.shadow_boat);
        commit('shadow_wooden', _shadowCounts.shadow_wooden);

        // ── Кувшинки (анимация — каждый кадр) ────────────────────────────────
        _shadowCounts.shadow_lilly = 0;
        for (let i = 0; i < world.lilys.length; i++) {
            const data = world.lilys[i];
            const wave = Math.sin(time * 2.0 + i * 1.3) * 0.02;
            const stableRot = Math.abs(Math.sin(data.x * 12.98 + data.z * 78.23) * Math.PI);
            let shakeY = 0, shakeRotX = 0;
            if (data.shakeTime) {
                if (data.shakeTime === -1) data.shakeTime = time;
                const age = time - data.shakeTime;
                if (age < 0.5) {
                    const decay = Math.exp(-age * 12), osc = Math.sin(age * 40);
                    shakeY    = osc * decay * 0.08;
                    shakeRotX = osc * decay * 0.22 * (data.shakeDir || 1);
                } else { data.shakeTime = 0; }
            }
            temp.position.set(data.x, -0.05 + (data.yOffset||0) + wave + shakeY, data.z);
            temp.rotation.set(shakeRotX, stableRot, 0);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            show('lily', i, temp.matrix);
            showShadow('shadow_lilly', data.x, data.z, SHADOW_Y_WATER);
        }
        commit('lily',         world.lilys.length);
        commit('shadow_lilly', _shadowCounts.shadow_lilly);

        // ── Гранаты (анимация — каждый кадр) ─────────────────────────────────
        const GRENADE_SHADOW_RADIUS = 1.5;
        const grenadeShade = (x, z) => {
            const row = _propsByZ.get(Math.round(z) - 1);
            if (!row) return 0;
            let minDist = Infinity;
            for (const px of row) minDist = Math.min(minDist, Math.abs(x - (px - 1)));
            return minDist < GRENADE_SHADOW_RADIUS ? 1 - minDist / GRENADE_SHADOW_RADIUS : 0;
        };

        const GRENADE_TYPE_TO_SHADOW = { HE: 'shadow_he', Flash: 'shadow_flashbang', Molotov: 'shadow_molotov' };
        const bGrenade = batches.grenade;
        _grenCounts.HE = _grenCounts.Flash = _grenCounts.Molotov = 0;
        _shadowCounts.shadow_he = _shadowCounts.shadow_flashbang = _shadowCounts.shadow_molotov = 0;
        let _grenadeColorDirty = false;
        for (const data of world.obstacles) {
            const key = data.type;
            const r   = data.rotation;
            const yFloat = data.hidden ? -1000 : 0.8 + Math.sin(time * 4 + data.phase) * 0.1;
            temp.position.set(data.x, yFloat, data.z);
            temp.rotation.set(r[0], r[1], r[2], 'YXZ');
            temp.rotation.z += data.direction * (data.speed * 0.05);
            temp.scale.set(1, 1, 1);
            temp.updateMatrix();
            const idx = _grenCounts[key]++;
            const entry = pools[`grenade_${key}`];
            show(`grenade_${key}`, idx, temp.matrix);
            if (entry && idx < entry.ids.length) {
                const t = grenadeShade(data.x, data.z);
                if (t > 0) {
                    bGrenade.setColorAt(entry.ids[idx], _grenadeColor.lerpColors(_grenadeLight, _grenadeDark, t));
                    _grenadeColorDirty = true;
                }
            }
            // Тень гранаты через GLB.
            // Читаем мировую проекцию длинной оси прямо из уже вычисленной матрицы гранаты.
            // Three.js хранит column-major: col2 (elements 8,9,10) = local Z в мире.
            // Длинная ось shadow-меша в GLB должна лежать вдоль local Z.
            if (!data.hidden) {
                const shadowKey = GRENADE_TYPE_TO_SHADOW[key];
                const shadIdx = _shadowCounts[shadowKey]++;
                const me = temp.matrix.elements;
                const wxZ = me[4], wzZ = me[6]; // XZ-проекция local-Y гранаты (длинная ось после GLTF-конвертации)
                const shadowAngle = Math.atan2(wxZ, wzZ);
                const shadowScale = Math.max(0.15, Math.hypot(wxZ, wzZ));
                const sunOffX = -(SUN_OFFSET[0] / SUN_OFFSET[1]) * yFloat * 0.5;
                const sunOffZ = -(SUN_OFFSET[2] / SUN_OFFSET[1]) * yFloat * 0.5;
                temp.position.set(data.x + sunOffX, SHADOW_Y_GROUND, data.z + sunOffZ);
                temp.rotation.set(0, shadowAngle, 0);
                temp.scale.set(1, 1, shadowScale);
                temp.updateMatrix();
                show(shadowKey, shadIdx, temp.matrix);
            }
        }
        if (bGrenade.instanceColor && _grenadeColorDirty) bGrenade.instanceColor.needsUpdate = true;
        commit('grenade_HE', _grenCounts.HE); commit('grenade_Flash', _grenCounts.Flash); commit('grenade_Molotov', _grenCounts.Molotov);
        commit('shadow_he', _shadowCounts.shadow_he); commit('shadow_flashbang', _shadowCounts.shadow_flashbang); commit('shadow_molotov', _shadowCounts.shadow_molotov);

        // ── Waterside (только при изменении воды) ─────────────────────────────
        if (watersDirty) {
            _prevWatersLen    = watersLen;
            _prevWatersFirstZ = watersFirstZ;
            let _watersideCount = 0;
            for (const z of world.waters) {
                for (const [dz, rotY] of [[-1, 0], [1, Math.PI]]) {
                    if (!world.waters.has(z + dz)) {
                        const pool = pools['waterside'];
                        if (!pool || _watersideCount >= pool.ids.length) break;
                        temp.position.set(0, 0, z);
                        temp.rotation.set(0, rotY, 0);
                        temp.scale.set(1, 1, 1);
                        temp.updateMatrix();
                        pool.b.setMatrixAt(pool.ids[_watersideCount], temp.matrix);
                        pool.b.setVisibleAt(pool.ids[_watersideCount], true);
                        _watersideCount++;
                    }
                }
            }
            commit('waterside', _watersideCount);
        }

        // ── Тени монет — scaleX сплющивается когда монета ребром ─────────────
        const _coinFloatY = 0.65;
        const _coinSunOffX = -(SUN_OFFSET[0] / SUN_OFFSET[1]) * _coinFloatY * 0.5;
        const _coinSunOffZ = -(SUN_OFFSET[2] / SUN_OFFSET[1]) * _coinFloatY * 0.5;
        _shadowCounts.shadow_coin = 0;
        for (const c of world.coins) {
            if (c.collected) continue;
            const shadIdx = _shadowCounts.shadow_coin++;
            const spinY = time * 2.8 + c.phase;
            const cosY = Math.cos(spinY);
            const scaleX = Math.max(0.12, Math.abs(cosY));
            const flipRotY = spinY + (cosY < 0 ? Math.PI : 0);
            temp.position.set(c.x + _coinSunOffX, SHADOW_Y_GROUND, c.z + _coinSunOffZ);
            temp.rotation.set(0, flipRotY, 0);
            temp.scale.set(scaleX, 1, 1);
            temp.updateMatrix();
            show('shadow_coin', shadIdx, temp.matrix);
        }
        commit('shadow_coin', _shadowCounts.shadow_coin);

        // ── Тени медалей ──────────────────────────────────────────────────────
        const _medalFloatY = 0.7;
        const _medalSunOffX = -(SUN_OFFSET[0] / SUN_OFFSET[1]) * _medalFloatY * 0.5;
        const _medalSunOffZ = -(SUN_OFFSET[2] / SUN_OFFSET[1]) * _medalFloatY * 0.5;
        _shadowCounts.shadow_part1 = _shadowCounts.shadow_part2 = _shadowCounts.shadow_part3 =
        _shadowCounts.shadow_part4 = _shadowCounts.shadow_part5 = 0;
        for (const m of world.medals) {
            if (m.collected) continue;
            const subtype = m.subtype ?? 'medal_part1';
            const shadowKey = subtype.startsWith('medal_') ? subtype.replace('medal_', 'shadow_') : 'shadow_part1';
            if (!_shadowCounts.hasOwnProperty(shadowKey)) continue;
            const shadIdx = _shadowCounts[shadowKey]++;
            const swayX = Math.sin(time * 1.1 + m.phase) * 0.22;
            const swayZ = Math.cos(time * 0.9 + m.phase + 1.0) * 0.18;
            const scaleX = 0.8 + Math.abs(Math.sin(swayZ)) * 0.35;
            const scaleZ = 0.8 + Math.abs(Math.sin(swayX)) * 0.35;
            temp.position.set(m.x + _medalSunOffX, SHADOW_Y_GROUND, m.z + _medalSunOffZ);
            temp.rotation.set(0, 0, 0);
            temp.scale.set(scaleX, 1, scaleZ);
            temp.updateMatrix();
            show(shadowKey, shadIdx, temp.matrix);
        }
        commit('shadow_part1', _shadowCounts.shadow_part1); commit('shadow_part2', _shadowCounts.shadow_part2);
        commit('shadow_part3', _shadowCounts.shadow_part3); commit('shadow_part4', _shadowCounts.shadow_part4);
        commit('shadow_part5', _shadowCounts.shadow_part5);

        // ── Dissolve: курица + монеты + медали → uniform ─────────────────────
        const pts = transpPointsUniform.value;
        let _ptIdx = 0;
        const _player = world.playerRef?.current;
        if (_player) { pts[_ptIdx++].set(_player.position.x, _player.position.z, 0.55, 1); }
        for (const c of world.coins) {
            if (!c.collected && _ptIdx < 4) { pts[_ptIdx++].set(c.x, c.z, 0.5, 1); }
        }
        for (const m of world.medals) {
            if (!m.collected && _ptIdx < 4) { pts[_ptIdx++].set(m.x, m.z, 0.5, 1); }
        }
        for (let i = _ptIdx; i < 4; i++) pts[i].w = 0;
        // Slots 4–7: lilies — only used when DISSOLVE_SLOTS > 4 (desktop)
        if (DISSOLVE_SLOTS > 4) {
            _ptIdx = 4;
            for (let i = 0; i < world.lilys.length; i++) {
                const _l = world.lilys[i];
                if (_ptIdx < DISSOLVE_SLOTS) { pts[_ptIdx++].set(_l.x, _l.z, 0.9, 1); }
            }
            for (let i = _ptIdx; i < DISSOLVE_SLOTS; i++) pts[i].w = 0;
        }
    });

    if (!batches) return null;
    return (
        <>
            <primitive object={batches.atlas} />
            <primitive object={batches.main} />
            <primitive object={batches.grenade} />
            <primitive object={batches.shadow} />
            <primitive object={batches.logo} />
        </>
    );
}

useGLTF.preload('/models/obstacle.glb');
useGLTF.preload('/models/wallwindow.glb');
useGLTF.preload('/models/wooden.glb');
useGLTF.preload('/models/boat.glb');
useGLTF.preload('/models/lilly.glb');
useGLTF.preload('/models/grenade.glb');
useGLTF.preload('/models/waterside.glb');
useGLTF.preload('/models/shadow.glb');
useGLTF.preload('/models/logo.glb');
