import { Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import Scene from "./Scene";
import Overlay from "./UI/Overlay";
import * as THREE from 'three'
import Loader from "./UI/Loader";
import PauseMenu from "./UI/PauseMenu";
import WardrobeMenu from "./UI/WardrobeMenu";
import PrizeMenu from "./UI/PrizeMenu";
import LeaderboardMenu from "./UI/LeaderboardMenu";
import InstructionMenu from "./UI/InstructionMenu";
import { GameWorldProvider } from "./Logic/GameWorldContext";
import { useGameStore } from "./Logic/store";

export default function Game() {
  const isMedalRevealOpen = useGameStore(s => s.isMedalRevealOpen);
  return (
    <div style={ { position: "fixed", top: 0, left: 0, right: 0, bottom: 'calc(-1 * env(safe-area-inset-bottom, 0px))', background: "#87CEEB" } }>
      <Loader />

      <Canvas
        style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}
        frameloop={isMedalRevealOpen ? 'never' : 'always'}
        dpr={[1, 1.5]}
        gl={ {
          precision: 'highp',
          antialias: false,
          powerPreference: 'high-performance',
          alpha: false,
          stencil: true,
          toneMapping: THREE.ACESFilmicToneMapping,
          toneMappingExposure: 1.35,
          outputColorSpace: THREE.SRGBColorSpace,
        } }
      >
        <Suspense fallback={ null }>
          <color attach="background" args={ ["#87CEEB"] } />
          <GameWorldProvider>
            <Scene />
          </GameWorldProvider>
        </Suspense>
      </Canvas>

      <Overlay />
      <PauseMenu />
      <WardrobeMenu />
      <PrizeMenu />
      <LeaderboardMenu />
      <InstructionMenu />
    </div>
  );
}