import { useEffect, useRef, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { WATER_Y, WATER_BOTTOM_OFFSET } from '../Logic/constants';
import WaterRowMaterialClass, { waterRowGeometry, rippleArray } from './WaterRowMaterial';
import { causticsGeo, causticsMaterial, bottomGeo, bottomMaterial } from './WaterBottomLayers';

const Y_OFFSET  = -1.75;
const SURFACE_Y = WATER_Y + Y_OFFSET;
const BOTTOM_Y  = SURFACE_Y - WATER_BOTTOM_OFFSET;
const Z_ROWS    = [-13, -14, -15, -16, -17];
const COUNT     = Z_ROWS.length;

const _temp    = new THREE.Object3D();
const _rotQuat = new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(1, 0, 0), -Math.PI / 2);

export default function StartWater() {
    const [meshes, setMeshes] = useState(null);
    const waterMatRef = useRef(null);

    useEffect(() => {
        const mat = new WaterRowMaterialClass();
        mat.transparent = true;
        mat.depthWrite  = false;
        waterMatRef.current = mat;

        const surface = new THREE.InstancedMesh(waterRowGeometry, mat, COUNT);
        surface.renderOrder   = 1;
        surface.frustumCulled = false;

        const bot = new THREE.InstancedMesh(bottomGeo, bottomMaterial, COUNT);
        bot.frustumCulled = false;

        const caust = new THREE.InstancedMesh(causticsGeo, causticsMaterial, COUNT);
        caust.renderOrder   = 2;
        caust.frustumCulled = false;

        _temp.quaternion.copy(_rotQuat);
        _temp.scale.set(1, 1, 1);

        Z_ROWS.forEach((z, i) => {
            _temp.position.set(0, BOTTOM_Y, z);
            _temp.updateMatrix();
            bot.setMatrixAt(i, _temp.matrix);

            _temp.position.set(0, SURFACE_Y, z);
            _temp.updateMatrix();
            surface.setMatrixAt(i, _temp.matrix);

            _temp.position.set(0, SURFACE_Y + 0.01, z);
            _temp.updateMatrix();
            caust.setMatrixAt(i, _temp.matrix);
        });

        bot.count     = COUNT;
        surface.count = COUNT;
        caust.count   = COUNT;

        bot.instanceMatrix.needsUpdate     = true;
        surface.instanceMatrix.needsUpdate = true;
        caust.instanceMatrix.needsUpdate   = true;

        setMeshes({ surface, bot, caust });

        return () => {
            mat.dispose();
            surface.dispose();
            bot.dispose();
            caust.dispose();
        };
    }, []);

    useFrame((state) => {
        if (!waterMatRef.current) return;
        waterMatRef.current.uniforms.uTime.value    = state.clock.elapsedTime;
        waterMatRef.current.uniforms.uRipples.value = rippleArray;
    });

    if (!meshes) return null;
    return (
        <>
            <primitive object={meshes.bot} />
            <primitive object={meshes.surface} />
            <primitive object={meshes.caust} />
        </>
    );
}
