const cardContentStyle = {
    paddingTop: 76,
    paddingBottom: 48,
    paddingLeft: 20,
    paddingRight: 20,
    alignItems: 'center',
    gap: 16,
};

const iconWrapStyle = {
    position: 'absolute',
    top: -29,
    left: '50%',
    transform: 'translateX(-50%)',
    zIndex: 10,
    pointerEvents: 'none',
};

const titleStyle = (C_CARD_SHADOW) => ({
    fontFamily: F_TITLE,
    fontWeight: 700,
    fontSize: 24,
    color: '#fff',
    textAlign: 'center',
    textShadow: `0 4px 0px ${C_CARD_SHADOW}`,
    letterSpacing: '2%',
});

const textBoxStyle = {
    width: '100%',
    background: '#292B36',
    border: '2px solid #3C4152',
    borderRadius: 8,
    padding: '24px 26px',
    boxSizing: 'border-box',
    boxShadow: 'inset 0 8px 4px #181A2799',
};

const textStyle = {
    margin: 0,
    fontFamily: F_UI,
    fontWeight: 600,
    fontSize: 14,
    letterSpacing: '4%',
    lineHeight: 1.2,
    color: '#ffffffCC',
    textShadow: '0 4px 0px #181A2799',
    textAlign: 'center',
};

export default function InstructionMenu() {
    const isIntroPlaying    = useGameStore(s => s.isIntroPlaying);
    const isInstructionOpen = useGameStore(s => s.isInstructionOpen);
    const isMoving          = useGameStore(s => s.isMoving);
    const restartTrigger    = useGameStore(s => s.restartTrigger);
    const t = useT();

    const hadIntro      = useRef(false);
    const introEnded    = useRef(false);
    const jumpShown     = useRef(false);
    const [page, setPage] = useState(1);
    const { counting, setCounting, startCountdown } = useCountdown();

    // Detect intro end
    useEffect(() => {
        if (isIntroPlaying) {
            hadIntro.current = true;
        } else if (hadIntro.current) {
            hadIntro.current = false;
            introEnded.current = true;
        }
    }, [isIntroPlaying]);

    // Show on first jump after intro
    useEffect(() => {
        if (!isMoving) return;
        if (!introEnded.current) return;
        if (jumpShown.current) return;
        if (localStorage.getItem(STORAGE_INSTRUCTION_SEEN)) return;
        jumpShown.current = true;
        useGameStore.setState({ isInstructionOpen: true, isPaused: true });
    }, [isMoving]);

    // Reset on lobby return
    useEffect(() => {
        hadIntro.current = false;
        introEnded.current = false;
        jumpShown.current = false;
        setCounting(null);
        setPage(1);
    }, [restartTrigger]);

    // counting===0 → dismiss + mark as seen
    useEffect(() => {
        if (counting !== 0) return;
        localStorage.setItem(STORAGE_INSTRUCTION_SEEN, '1');
        useGameStore.setState({ isInstructionOpen: false, isPaused: false });
        setCounting(null);
    }, [counting]);

    if (!isInstructionOpen) return null;

    const goToPage2 = () => setPage(2);

    return (
        <div
            style={{
                position: 'fixed', inset: 0, zIndex: 3100,
                background: counting !== null ? 'transparent' : OVERLAY_BG,
                backdropFilter: counting !== null ? 'none' : 'blur(10px)',
                WebkitBackdropFilter: counting !== null ? 'none' : 'blur(10px)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                paddingLeft: 18, paddingRight: 18,
                animation: 'imFadeIn 0.25s ease-out',
            }}
        >
            {/* Page 1 — movement instructions */}
            {counting === null && page === 1 && (
                <div key="page1" style={{ position: 'relative', width: '100%', maxWidth: 360, animation: 'imFadeIn 0.2s ease-out' }}>
                    <div style={iconWrapStyle}>
                        <IconMove />
                    </div>
                    <GameCard style={cardContentStyle}>
                        <div style={titleStyle(C_CARD_SHADOW)}>{t.instructionTitle}</div>
                        <div style={textBoxStyle}>
                            <p style={textStyle}>{t.instructionText}</p>
                        </div>
                        <GameButton
                            onPointerDown={(e) => { e.stopPropagation(); goToPage2(); }}
                            shadowColor={C_BTN_SHADOW}
                            bg={OG_GRAD}
                            color="#fff"
                            textShadow={`0 3px 0px ${C_BTN_SHADOW}`}
                            wrapperStyle={{ width: '75%', marginTop: 8 }}
                            style={{ fontFamily: F_TITLE, fontWeight: 700, fontSize: 22 }}
                        >
                            {t.instructionNextBtn}
                        </GameButton>
                    </GameCard>
                </div>
            )}

            {/* Page 2 — medal instructions */}
            {counting === null && page === 2 && (
                <div key="page2" style={{ position: 'relative', width: '100%', maxWidth: 360, animation: 'imFadeIn 0.2s ease-out' }}>
                    <div style={iconWrapStyle}>
                        <img
                            src="/images/medalRio2026.webp"
                            alt="medal"
                            style={{ width: 90, height: 90, objectFit: 'contain', display: 'block' }}
                        />
                    </div>
                    <GameCard style={cardContentStyle}>
                        <div style={titleStyle(C_CARD_SHADOW)}>{t.instructionTitle2}</div>
                        <div style={textBoxStyle}>
                            <p style={textStyle}>{t.instructionText2}</p>
                        </div>
                        <GameButton
                            onPointerDown={(e) => { e.stopPropagation(); startCountdown(); }}
                            shadowColor={C_BTN_SHADOW}
                            bg={OG_GRAD}
                            color="#fff"
                            textShadow={`0 3px 0px ${C_BTN_SHADOW}`}
                            wrapperStyle={{ width: '75%', marginTop: 8 }}
                            style={{ fontFamily: F_TITLE, fontWeight: 700, fontSize: 22 }}
                        >
                            {t.instructionBtn}
                        </GameButton>
                    </GameCard>
                </div>
            )}

            {counting !== null && <CountdownNumber key={counting} value={counting} />}

            <style>{`
                @keyframes imFadeIn {
                    from { opacity: 0; transform: scale(0.95); }
                    to   { opacity: 1; transform: scale(1); }
                }
            `}</style>
        </div>
    );
}
