import { useMemo } from 'react';
import { useGLTF } from '@react-three/drei';
import { sharedChickenMaterial } from '../View/sharedMaterial';

const colorAttrName = (idx) => idx === 0 ? 'color' : `color_${idx}`;

export default function Chicken({ colorIdx = 0, material, ...props }) {
    const { nodes } = useGLTF('/models/chicken.glb');

    const geometry = useMemo(() => {
        const base = nodes.modelschickenchickenvmdl_cchicken008?.geometry;
        if (!base) return null;
        const attrName = colorAttrName(colorIdx);
        const targetAttr = base.attributes[attrName];
        if (!targetAttr || attrName === 'color') return base;
        const cloned = base.clone();
        cloned.setAttribute('color', targetAttr);
        return cloned;
    }, [nodes, colorIdx]);

    if (!geometry) return null;

    return (
        <group {...props} dispose={null}>
            <mesh
                geometry={geometry}
                material={material ?? sharedChickenMaterial}
            />
        </group>
    );
}

useGLTF.preload('/models/chicken.glb');
