import { create } from 'zustand';
import { PhysicsManager } from './PhysicsEngine';
import {
    STORAGE_COINS, STORAGE_SOUND, STORAGE_UNLOCKED,
    STORAGE_HIGHSCORE, STORAGE_TOP_SCORES, STORAGE_CHICKEN_COLOR, STORAGE_LANG,
    COIN_VALUE_GOLD, COIN_VALUE_RED, COIN_TYPE_RED,
    MEDALS_FOR_INVUL, SCORE_BOOST_PER_ROW,
    UPGRADE_SLOW_DURATION, UPGRADE_SCORE_DURATION, UPGRADE_INVUL_HITS,
    SPEED_SCORE_STEP, SPEED_INCREMENT,
    DEATH_BONUS_STEP, DEATH_BONUS_COINS,
    STORAGE_JWT, STORAGE_EMAIL, CHICKPOINT_URL, CHICKPOINT_URL_BR,
} from './constants';
import { apiAuthWithEmail, apiLogout, apiLogoutAll, apiGetMe, apiGetProfile, apiStartSession, apiSubmitScore, apiGetOwnedSkins, apiBuySkin, apiSetActiveSkin, apiGetCountry, apiGetMyPrizes, apiGetMvpSettings, apiGetShop } from './api';

// ── Profile sync (login + session restore) ────────────────────────────────────
const FREE_AUTH_SKINS = ['chicken_color_0', 'chicken_color_15', 'chicken_color_16', 'chicken_color_17'];
const FREE_AUTH_BACKEND_IDS = { chicken_color_0: 1, chicken_color_15: 2, chicken_color_16: 3, chicken_color_17: 4 };

async function syncProfile(token, set, isNew = false) {
    const [profileRes, skinsRes] = await Promise.all([
        apiGetProfile(token),
        apiGetOwnedSkins(token),
    ]);

    const p = profileRes.data ?? profileRes;
    const serverHighScore = p.best_score ?? 0;
    const serverCoins     = p.coins ?? 0;
    localStorage.setItem(STORAGE_HIGHSCORE, serverHighScore);
    localStorage.setItem(STORAGE_COINS, serverCoins);

    const serverSkins = Array.isArray(skinsRes.data) ? skinsRes.data : [];
    const serverOwnedCodes = new Set(serverSkins.map(s => s.code).filter(Boolean));

    for (const id of FREE_AUTH_SKINS) {
        if (isNew && !serverOwnedCodes.has(id)) {
            apiBuySkin(token, FREE_AUTH_BACKEND_IDS[id]).catch(() => {});
        }
        serverOwnedCodes.add(id);
    }

    const newUnlocked = [...serverOwnedCodes];
    localStorage.setItem(STORAGE_UNLOCKED, JSON.stringify(newUnlocked));

    // active_skin: null → Wilson (chicken_color_0, colorIdx 0)
    const activeSkinCode = p.active_skin?.code ?? 'chicken_color_0';
    const m = activeSkinCode.match(/^chicken_color_(\d+)$/);
    const activeColorIdx = m ? parseInt(m[1], 10) : 0;
    localStorage.setItem(STORAGE_CHICKEN_COLOR, activeColorIdx);

    set({
        highScore:      serverHighScore,
        totalCoins:     serverCoins,
        unlockedItems:  newUnlocked,
        chickenColorIdx: activeColorIdx,
    });
}

// Module-level timer endpoints (performance.now timestamps).
// Updated directly — no Zustand set() per frame, no re-renders while counting down.
export const upgradeTimers = { slowMotionEndAt: 0, scoreBoostEndAt: 0 };


// Stored timer IDs to allow cleanup on repeated calls
let _flashTimer      = null;
let _flashOnCooldown = false;
let _invulTimer   = null;
const savedCoins      = parseInt(localStorage.getItem(STORAGE_COINS) || '0', 10);
const savedSound      = localStorage.getItem(STORAGE_SOUND) !== 'false';
const savedUnlocked   = JSON.parse(localStorage.getItem(STORAGE_UNLOCKED)   || '[]').filter(id => id.startsWith('chicken_color_'));
const savedHighScore  = parseInt(localStorage.getItem(STORAGE_HIGHSCORE)    || '0', 10);
const savedTopScores  = JSON.parse(localStorage.getItem(STORAGE_TOP_SCORES) || '[]');
const savedChickenColor = parseInt(localStorage.getItem(STORAGE_CHICKEN_COLOR) || '0', 10);
const savedLang = localStorage.getItem(STORAGE_LANG) ?? 'pt';

export const useGameStore = create((set, get) => ({
    isDead: false,
    score: 0,
    deathType: null,
    isAuth: !!localStorage.getItem(STORAGE_JWT),
    setAuth: (v) => set({ isAuth: v }),
    isAuthModalOpen: false,
    openAuthModal:  () => set({ isAuthModalOpen: true }),
    closeAuthModal: () => set({ isAuthModalOpen: false }),

    // ── Backend auth ──────────────────────────────────────────────────────────
    jwt:          localStorage.getItem(STORAGE_JWT)   || null,
    userEmail:    localStorage.getItem(STORAGE_EMAIL) || null,
    sessionToken: null,
    sessionCoins: 0,
    sessionStartedAt: null,

    loginAsync: async (email, password) => {
        const { token, email: resolvedEmail, isNew } = await apiAuthWithEmail(email, password);
        localStorage.setItem(STORAGE_JWT, token);
        localStorage.setItem(STORAGE_EMAIL, resolvedEmail ?? email);

        set({ isAuth: true, jwt: token, userEmail: resolvedEmail ?? email });
        get().fetchMyPrizes();

        const { isStarted, isDead, score, sessionCoins, sessionStartedAt } = get();
        if (isStarted && !isDead) {
            // Логин во время игры — стартуем сессию, потом синхронизируем профиль
            get().startGameSession();
            try { await syncProfile(token, set, isNew); } catch (_) { /* non-fatal */ }
        } else if (isStarted && isDead) {
            // Логин на экране смерти — стартуем сессию, сабмитим счёт, потом синхронизируем профиль
            try {
                const data = await apiStartSession(token);
                const sessionToken = data.data?.session_token ?? data.session_token;
                if (sessionToken) {
                    const durationSec = sessionStartedAt ? Math.floor((Date.now() - sessionStartedAt) / 1000) : 0;
                    await apiSubmitScore(token, sessionToken, score, sessionCoins, durationSec);
                }
            } catch (_) { /* non-fatal */ }
            try { await syncProfile(token, set, isNew); } catch (_) { /* non-fatal */ }
        } else {
            try { await syncProfile(token, set, isNew); } catch (_) { /* non-fatal */ }
        }
    },

    logoutAction: () => {
        const { jwt } = get();
        if (jwt) apiLogout(jwt).catch(() => {});
        localStorage.removeItem(STORAGE_JWT);
        localStorage.removeItem(STORAGE_EMAIL);
        localStorage.setItem(STORAGE_CHICKEN_COLOR, 0);
        set({ isAuth: false, jwt: null, userEmail: null, sessionToken: null, sessionStartedAt: null, chickenColorIdx: 0 });
    },

    logoutAllDevicesAction: () => {
        const { jwt } = get();
        if (jwt) apiLogoutAll(jwt).catch(() => {});
        localStorage.removeItem(STORAGE_JWT);
        localStorage.removeItem(STORAGE_EMAIL);
        localStorage.setItem(STORAGE_CHICKEN_COLOR, 0);
        set({ isAuth: false, jwt: null, userEmail: null, sessionToken: null, sessionStartedAt: null, chickenColorIdx: 0 });
    },

    chickpointUrl: CHICKPOINT_URL,
    mvpSettings: null,   // { mvp_link, is_active } | null
    myPrizes: [],
    fetchMyPrizes: async () => {
        const { jwt } = get();
        if (!jwt) return;
        try {
            const res = await apiGetMyPrizes(jwt);
            const list = res.data ?? res;
            if (Array.isArray(list)) set({ myPrizes: list });
        } catch (_) { /* non-fatal */ }
    },

    // ── Skin prices from server ───────────────────────────────────────────────
    skinPrices: {},   // { [skinCode]: price }
    fetchSkinPrices: async () => {
        try {
            const res = await apiGetShop();
            const items = res.data ?? res;
            if (!Array.isArray(items)) return;
            const prices = {};
            for (const item of items) {
                if (item.code && item.price != null) prices[item.code] = item.price;
            }
            if (Object.keys(prices).length > 0) set({ skinPrices: prices });
        } catch (_) { /* non-fatal */ }
    },

    _geoInitialized: false,
    initGeoUrl: async () => {
        if (get()._geoInitialized) return;
        set({ _geoInitialized: true });
        try {
            const res = await apiGetCountry();
            const country = res.data?.country ?? res.country ?? '';
            const region = country.toUpperCase() === 'BR' ? 'brazil' : 'main';
            if (region === 'brazil' && CHICKPOINT_URL_BR) set({ chickpointUrl: CHICKPOINT_URL_BR });
            try {
                const mvpRes = await apiGetMvpSettings(region);
                set({ mvpSettings: mvpRes.data ?? mvpRes });
            } catch (_) { /* non-fatal */ }
        } catch (_) { /* non-fatal */ }
    },

    restoreSession: async () => {
        const jwt = localStorage.getItem(STORAGE_JWT);
        if (!jwt) return;
        try {
            await apiGetMe(jwt);
            try { await syncProfile(jwt, set); } catch (_) { /* non-fatal */ }
            get().fetchMyPrizes();
        } catch (e) {
            if (e.status === 401) {
                localStorage.removeItem(STORAGE_JWT);
                localStorage.removeItem(STORAGE_EMAIL);
                set({ isAuth: false, jwt: null, userEmail: null });
            }
        }
    },

    startGameSession: async () => {
        const { jwt } = get();
        if (!jwt) return;
        try {
            const data = await apiStartSession(jwt);
            const token = data.data?.session_token ?? data.session_token;
            set({ sessionToken: token, sessionStartedAt: Date.now() });
        } catch (_) { /* non-fatal */ }
    },
    seed: Math.random(),
    explosionPos: [0, 0, 0],
    isInvulnerable: false,
    isFlashed: false,
    restartTrigger: 0,
    isNewRecord: false,

    // ── Медали и апгрейды ─────────────────────────────────────────────────────
    medalPartsCollected: [],
    upgradeMenuOpen: false,
    upgradeMenuIsFirst: true,      // первый раз — без таймера
    // Щит (hit-based invulnerability)
    invulnerabilityActive: false,
    invulnerabilityHitsLeft: 0,
    // Замедление
    slowMotionActive: false,
    // Двойные очки
    scoreBoostActive: false,
    scoreBonus: 0,

    highScore: savedHighScore,
    topScores: savedTopScores,

    chickenColorIdx: savedChickenColor,
    setChickenColor: (idx, backendId) => {
        localStorage.setItem(STORAGE_CHICKEN_COLOR, idx);
        set({ chickenColorIdx: idx });
        const { jwt } = get();
        if (jwt && backendId != null) apiSetActiveSkin(jwt, backendId).catch(() => {});
    },
    buyChickenColor: (idx, cost, backendId) => {
        const id = `chicken_color_${idx}`;
        const { unlockedItems, totalCoins } = get();
        if (unlockedItems.includes(id) || totalCoins < cost) return false;
        const newTotal    = totalCoins - cost;
        const newUnlocked = [...unlockedItems, id];
        localStorage.setItem(STORAGE_COINS, newTotal);
        localStorage.setItem(STORAGE_UNLOCKED, JSON.stringify(newUnlocked));
        set({ totalCoins: newTotal, unlockedItems: newUnlocked, chickenColorIdx: idx });
        localStorage.setItem(STORAGE_CHICKEN_COLOR, idx);
        const { jwt } = get();
        if (jwt && backendId != null) apiBuySkin(jwt, backendId).catch(() => {});
        return true;
    },  // [{ score, date }] — топ-10

    isWardrobeOpen: false,
    openWardrobe:  () => set({ isWardrobeOpen: true }),
    closeWardrobe: () => set({ isWardrobeOpen: false }),
    closeWardrobeAll: () => set({ isWardrobeOpen: false, isPaused: false }),

    isChestOpen: false,
    openChest:   () => set({ isChestOpen: true }),
    closeChest:  () => set({ isChestOpen: false }),
    closeChestAll: () => set({ isChestOpen: false, isPaused: false }),

    isLeaderboardOpen: false,
    openLeaderboard:   () => set({ isLeaderboardOpen: true }),
    closeLeaderboard:  () => set({ isLeaderboardOpen: false }),
    closeLeaderboardAll: () => set({ isLeaderboardOpen: false, isPaused: false }),

    isPaused: false,
    togglePause: () => set(s => ({ isPaused: !s.isPaused })),

    isMedalRevealOpen: false,
    setMedalRevealOpen: (v) => set({ isMedalRevealOpen: v }),

    isStarted: false,
    isCameraReady: true,
    setStarted: () => { set({ isStarted: true, sessionCoins: 0, sessionStartedAt: Date.now() }); get().startGameSession(); },

    lobbyTab: 'play',
    setLobbyTab: (tab) => set({ lobbyTab: tab }),

    isIntroPlaying: false,
    isInstructionOpen: false,

    soundEnabled: savedSound,
    toggleSound: () => {
        const next = !get().soundEnabled;
        localStorage.setItem(STORAGE_SOUND, next);
        set({ soundEnabled: next });
    },

    language: savedLang,
    setLanguage: (lang) => {
        localStorage.setItem(STORAGE_LANG, lang);
        set({ language: lang });
    },

    // ── Инвентарь ─────────────────────────────────────────────────────────────
    unlockedItems: savedUnlocked,  // string[] — chicken_color_* ids
    totalCoins: savedCoins,
    collectCoin: (type) => {
        const add = type === COIN_TYPE_RED ? COIN_VALUE_RED : COIN_VALUE_GOLD;
        const newTotal = get().totalCoins + add;
        localStorage.setItem(STORAGE_COINS, newTotal);
        set({ totalCoins: newTotal, sessionCoins: get().sessionCoins + add });
    },

    // ── Сбор части медали → открывает меню апгрейда ──────────────────────────
    collectPartMedal: (subtype) => {
        const parts = get().medalPartsCollected;
        if (parts.includes(subtype)) return false;
        const next = [...parts, subtype];
        if (next.length >= MEDALS_FOR_INVUL) {
            set({ medalPartsCollected: [], upgradeMenuOpen: true });
            return true;
        }
        set({ medalPartsCollected: next });
        return false;
    },

    // ── Выбор апгрейда ────────────────────────────────────────────────────────
    selectUpgrade: (type) => {
        const base = { upgradeMenuOpen: false, upgradeMenuIsFirst: false };
        if (type === 'slowmo') {
            upgradeTimers.slowMotionEndAt = performance.now() + UPGRADE_SLOW_DURATION * 1000;
            set({ ...base, slowMotionActive: true });
        } else if (type === 'shield') {
            const cur = get().invulnerabilityHitsLeft;
            const next = Math.min(cur + 1, UPGRADE_INVUL_HITS);
            set({ ...base, invulnerabilityActive: true, invulnerabilityHitsLeft: next });
        } else if (type === 'doublescore') {
            upgradeTimers.scoreBoostEndAt = performance.now() + UPGRADE_SCORE_DURATION * 1000;
            set({ ...base, scoreBoostActive: true });
        }
    },

    // ── Поглощение удара щитом ────────────────────────────────────────────────
    shieldHit: () => {
        const hits = get().invulnerabilityHitsLeft - 1;
        if (hits <= 0) set({ invulnerabilityActive: false, invulnerabilityHitsLeft: 0 });
        else           set({ invulnerabilityHitsLeft: hits });
    },

    // ── Bomb & Sniper ─────────────────────────────────────────────────────────
    bombActive: false,
    bombProgress: 0,    // 0→1 за 5 сек
    sniperActive: false,
    sniperProgress: 0,  // 0→1
    backSteps: 0,       // сколько шагов назад подряд сделано
    forwardSteps: 0,    // шаги вперёд подряд (для сброса снайпера через 5)
    setBombProgress:   (v) => set({ bombActive: v > 0, bombProgress: v }),
    setSniperProgress: (v) => set({ sniperActive: v > 0, sniperProgress: v }),

    getSpeedMultiplier: () => {
        const currentScore = get().score;
        return 1 + Math.floor(currentScore / SPEED_SCORE_STEP) * SPEED_INCREMENT;
    },

    die: (type, pos) => {
        if (get().isDead) return;
        const score = get().score;

        const bonus = Math.floor(score / DEATH_BONUS_STEP) * DEATH_BONUS_COINS;
        const newTotal = get().totalCoins + bonus;
        if (bonus > 0) {
            localStorage.setItem(STORAGE_COINS, newTotal);
            set({ sessionCoins: get().sessionCoins + bonus });
        }

        // Highscore
        const isNewRecord = score > 0 && score > get().highScore;
        const newHighScore = Math.max(get().highScore, score);
        if (isNewRecord) localStorage.setItem(STORAGE_HIGHSCORE, newHighScore);

        // Топ-10 (только если score > 0)
        const newTopScores = score > 0
            ? [...get().topScores, { score, date: Date.now() }]
                .sort((a, b) => b.score - a.score)
                .slice(0, 10)
            : get().topScores;
        if (score > 0) localStorage.setItem(STORAGE_TOP_SCORES, JSON.stringify(newTopScores));

        set({
            isDead: true,
            deathType: type,
            explosionPos: pos,
            isNewRecord,
            highScore: newHighScore,
            topScores: newTopScores,
            ...(bonus > 0 ? { totalCoins: newTotal } : {}),
        });

        // Submit score to backend (fire-and-forget)
        const { jwt, sessionToken, sessionCoins, sessionStartedAt } = get();
        if (jwt && sessionToken) {
            const durationSec = sessionStartedAt ? Math.floor((Date.now() - sessionStartedAt) / 1000) : 0;
            apiSubmitScore(jwt, sessionToken, score, sessionCoins, durationSec).catch(() => {});
            set({ sessionToken: null, sessionCoins: 0, sessionStartedAt: null });
        }
    },

    flash: () => {
        if (_flashOnCooldown) return;
        set({ isFlashed: true });
        if (_flashTimer) clearTimeout(_flashTimer);
        _flashTimer = setTimeout(() => {
            _flashTimer = null;
            set({ isFlashed: false });
            _flashOnCooldown = true;
            setTimeout(() => { _flashOnCooldown = false; }, 1000);
        }, 2000);
    },

    addScore: (z) => set((state) => {
        const bonus = state.scoreBoostActive ? state.scoreBonus + SCORE_BOOST_PER_ROW : state.scoreBonus;
        return { score: Math.max(state.score, Math.floor(z) + bonus), scoreBonus: bonus };
    }),

    goToLobby: () => {
        upgradeTimers.slowMotionEndAt = 0;
        upgradeTimers.scoreBoostEndAt = 0;
        if (_flashTimer) { clearTimeout(_flashTimer); _flashTimer = null; }
        _flashOnCooldown = false;
        PhysicsManager.clearAll();
        const wasStarted = get().isStarted;
        set({
            isStarted: false,
            // Only hide TAP TO PLAY if we were in-game — camera return animation will show it again.
            // If already on start screen, isStarted won't change so SmartCamera won't fire.
            isCameraReady: wasStarted ? false : true,
            isIntroPlaying: false,
            isInstructionOpen: false,
            isDead: false,
            isPaused: false,
            score: 0,
            deathType: null,
            isFlashed: false,
            isNewRecord: false,
            bombActive: false, bombProgress: 0,
            sniperActive: false, sniperProgress: 0,
            backSteps: 0, forwardSteps: 0,
            explosionPos: [0, 0, 0],
            seed: Math.random(),
            restartTrigger: get().restartTrigger + 1,
            medalPartsCollected: [],
            upgradeMenuOpen: false,
            upgradeMenuIsFirst: true,
            invulnerabilityActive: false,
            invulnerabilityHitsLeft: 0,
            slowMotionActive: false,
            scoreBoostActive: false,
            scoreBonus: 0,
            isMoving: false,
        });
    },

    restart: () => {
        upgradeTimers.slowMotionEndAt = 0;
        upgradeTimers.scoreBoostEndAt = 0;
        if (_flashTimer) { clearTimeout(_flashTimer); _flashTimer = null; }
        _flashOnCooldown = false;
        // 1. ОЧИЩАЕМ ФИЗИЧЕСКИЙ МИР
        PhysicsManager.clearAll();

        // 2. СБРАСЫВАЕМ СОСТОЯНИЕ И СИД
        set({
            isDead: false,
            score: 0,
            deathType: null,
            isFlashed: false,
            isInvulnerable: true,
            isNewRecord: false,
            bombActive: false, bombProgress: 0,
            sniperActive: false, sniperProgress: 0,
            backSteps: 0,
            forwardSteps: 0,
            explosionPos: [0, 0, 0],
            seed: Math.random(),
            restartTrigger: get().restartTrigger + 1,
            sessionCoins: 0,
            // Сбрасываем медали и апгрейды
            medalPartsCollected: [],
            upgradeMenuOpen: false,
            upgradeMenuIsFirst: true,
            invulnerabilityActive: false,
            invulnerabilityHitsLeft: 0,
            slowMotionActive: false,
            scoreBoostActive: false,
            scoreBonus: 0,
            isMoving: false,
        });

        if (_invulTimer) clearTimeout(_invulTimer);
        _invulTimer = setTimeout(() => { _invulTimer = null; set({ isInvulnerable: false }); }, 500);

        // Start new backend session for the restarted round
        get().startGameSession();
    }
}));