import { useGLTF } from '@react-three/drei';
import ktx2Loader from '../View/ktx2Loader';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useMemo, useRef, useEffect } from 'react';
import { sharedAtlasMaterial, sharedLogoMaterial, sharedShadowMaterial } from '../View/sharedMaterial';

const startMaterial = new THREE.MeshStandardMaterial({
    roughness: 0.82,
    metalness: 0.0,
});

useGLTF.preload('/models/start.glb');

export default function StartLocation() {
    const { nodes } = useGLTF('/models/start.glb');
    const boatRef  = useRef();
    const boatBase = useRef(null); // base position read on first frame

    useEffect(() => {
        ktx2Loader.load('/images/textureAtlasStart.ktx2', (tex) => {
            tex.colorSpace = THREE.SRGBColorSpace;
            tex.flipY      = false;
            tex.minFilter  = THREE.LinearMipmapLinearFilter;
            tex.magFilter  = THREE.LinearFilter;
            startMaterial.map = tex;
            startMaterial.needsUpdate = true;
        });
    }, []);

    const { staticMeshes, boatMesh, logoBoatMesh, logoGrafMesh } = useMemo(() => {
        const all = Object.values(nodes).filter(n => n.isMesh);
        const animated = new Set(['inflatable_boat', 'logoMain_Boat', 'logoGraf1', 'logoGraf2']);
        return {
            boatMesh:     all.find(n => n.name === 'inflatable_boat'),
            logoBoatMesh: all.find(n => n.name === 'logoMain_Boat'),
            logoGrafMesh: all.filter(n => n.name === 'logoGraf1' || n.name === 'logoGraf2'),
            staticMeshes: all.filter(n => !animated.has(n.name)),
        };
    }, [nodes]);

    useFrame(({ clock }) => {
        if (!boatRef.current) return;
        if (boatBase.current === null) {
            boatBase.current = boatRef.current.position.clone();
        }
        const t = clock.getElapsedTime();
        boatRef.current.position.set(
            boatBase.current.x,
            boatBase.current.y + Math.sin(t * 1.5) * 0.04,
            boatBase.current.z
        );
        boatRef.current.rotation.x = Math.sin(t * 1.5) * 0.05;
        boatRef.current.rotation.z = Math.sin(t * 1.1 + 0.8) * 0.03;
    });

    return (
        <group>
            {staticMeshes.map(mesh => (
                <mesh
                    key={mesh.name}
                    geometry={mesh.geometry}
                    material={mesh.name.includes('_START') ? sharedAtlasMaterial : startMaterial}
                    position={[0, 0, 0]}
                />
            ))}
            {(boatMesh || logoBoatMesh) && (
                <group ref={boatRef} position={[-1.09615, -1.79778, -14.7933]}>
                    {boatMesh && (
                        <mesh geometry={boatMesh.geometry} material={startMaterial} />
                    )}
                    {logoBoatMesh && (
                        <mesh geometry={logoBoatMesh.geometry} material={sharedLogoMaterial} />
                    )}
                </group>
            )}
            {logoGrafMesh.map(mesh => (
                <mesh key={mesh.name} geometry={mesh.geometry} material={sharedLogoMaterial} />
            ))}
        </group>
    );
}
