import { useGLTF } from '@react-three/drei';
import { useFrame } from '@react-three/fiber';
import { useEffect, useRef, useState, useLayoutEffect } from 'react';
import * as THREE from 'three';
import { useWorld } from '../Logic/GameWorldContext';
import { MAX_COINS, MAX_MEDALS, POOL_SHADOW_MEDAL_PART } from '../Logic/constants';
import { coinAtlasMaterial } from './sharedMaterial';
import { useGameStore } from '../Logic/store';

const temp = new THREE.Object3D();

// ── Пулы экземпляров ───────────────────────────────────────────────────────────
const POOL_CM = {
    coin_gold:    MAX_COINS,              // 150
    coin_red:     MAX_COINS,              // 150
    medal_part1:  POOL_SHADOW_MEDAL_PART, // 12
    medal_part2:  POOL_SHADOW_MEDAL_PART,
    medal_part3:  POOL_SHADOW_MEDAL_PART,
    medal_part4:  POOL_SHADOW_MEDAL_PART,
    medal_part5:  POOL_SHADOW_MEDAL_PART,
};
const TOTAL_CM = Object.values(POOL_CM).reduce((s, n) => s + n, 0);

// ── Искры монет ────────────────────────────────────────────────────────────────
const coinSparkGeo = new THREE.OctahedronGeometry(0.065, 0);
const coinSparkMat = new THREE.MeshBasicMaterial({ color: '#ffffff' });
const IDLE_PER_COIN  = 2;
const BURST_COUNT    = 12;
const MAX_BURSTS     = 8;
const MAX_COIN_SPARKS = MAX_COINS * IDLE_PER_COIN + MAX_BURSTS * BURST_COUNT;
const COLLECT_ANIM   = 0.35;
const BURST_LIFETIME = 0.6;

const burstPool = Array.from({ length: MAX_BURSTS }, () => ({
    active: false, x: 0, y: 0, z: 0, startTime: 0,
    dirs: Array.from({ length: BURST_COUNT }, () => ({ vx: 0, vz: 0 })),
}));

const activateBurst = (x, y, z, time) => {
    const slot = burstPool.find(b => !b.active) ?? burstPool[0];
    slot.active = true; slot.x = x; slot.y = y; slot.z = z; slot.startTime = time;
    for (let i = 0; i < BURST_COUNT; i++) {
        const angle  = (i / BURST_COUNT) * Math.PI * 2 + (Math.random() - 0.5) * 0.4;
        const radius = 1.5 + Math.random() * 1.5;
        slot.dirs[i].vx = Math.cos(angle) * radius;
        slot.dirs[i].vz = Math.sin(angle) * radius;
    }
};

// ── Искры медалей ──────────────────────────────────────────────────────────────
const medalSparkGeo = new THREE.OctahedronGeometry(0.045, 0);
const medalSparkMat = new THREE.MeshBasicMaterial({ color: '#ffd700' });
const IDLE_SPARKS_PER_MEDAL  = 3;
const MAX_MEDAL_SPARKS        = MAX_MEDALS * IDLE_SPARKS_PER_MEDAL;
const MEDAL_COLLECT_DURATION  = 0.9;

export default function CoinMedalBatchView() {
    const { nodes: coinNodes  } = useGLTF('/models/coin.glb');
    const { nodes: medalNodes } = useGLTF('/models/medal.glb');
    const world = useWorld();

    const [batch, setBatch]     = useState(null);
    const poolsRef              = useRef({});
    const prevRef               = useRef({});
    const coinSparkRef          = useRef();
    const medalSparkRef         = useRef();

    // Сбрасываем burst-частицы при рестарте (module-level pool, персистентный между играми)
    useEffect(() => useGameStore.subscribe(
        s => s.restartTrigger,
        () => { for (let i = 0; i < burstPool.length; i++) burstPool[i].active = false; }
    ), []);

    // ── Строим BatchedMesh один раз при готовности геометрий ──────────────────
    useEffect(() => {
        const geoMap = {
            coin_gold:   coinNodes.coin_gold?.geometry,
            coin_red:    coinNodes.coin_red?.geometry,
            medal_part1: medalNodes.medal_part1?.geometry,
            medal_part2: medalNodes.medal_part2?.geometry,
            medal_part3: medalNodes.medal_part3?.geometry,
            medal_part4: medalNodes.medal_part4?.geometry,
            medal_part5: medalNodes.medal_part5?.geometry,
        };
        if (Object.values(geoMap).some(g => !g)) return;

        let verts = 0, idx = 0;
        Object.values(geoMap).forEach(geo => {
            verts += geo.attributes.position.count;
            idx   += geo.index ? geo.index.count : geo.attributes.position.count;
        });

        const b = new THREE.BatchedMesh(TOTAL_CM, verts, idx, coinAtlasMaterial);
        b.frustumCulled          = false;
        b.perObjectFrustumCulled = false;

        const pools = {};
        const prev  = {};
        Object.entries(POOL_CM).forEach(([key, count]) => {
            const geoId = b.addGeometry(geoMap[key]);
            const ids   = [];
            for (let i = 0; i < count; i++) {
                const id = b.addInstance(geoId);
                b.setVisibleAt(id, false);
                ids.push(id);
            }
            pools[key] = ids;
            prev[key]  = 0;
        });

        poolsRef.current = pools;
        prevRef.current  = prev;
        setBatch(b);

        return () => {
            b.dispose();
            setBatch(null);
        };
    }, [coinNodes, medalNodes]);

    // Сброс count спарклей при монтировании
    useLayoutEffect(() => {
        if (coinSparkRef.current)  coinSparkRef.current.count  = 0;
        if (medalSparkRef.current) medalSparkRef.current.count = 0;
    }, []);

    useFrame((state) => {
        if (!batch) return;
        const b = batch;

        const time  = state.clock.elapsedTime;
        const pools = poolsRef.current;
        const prev  = prevRef.current;
        const coins  = world.coins;
        const medals = world.medals;

        // Счётчики использования — сбрасываем каждый кадр
        const counts = {};
        for (const k in POOL_CM) counts[k] = 0;

        const show = (key, matrix) => {
            const idx = counts[key]++;
            const ids = pools[key];
            if (!ids || idx >= ids.length) return;
            b.setMatrixAt(ids[idx], matrix);
            b.setVisibleAt(ids[idx], true);
        };

        const commit = (key) => {
            const ids     = pools[key];
            const newCnt  = counts[key];
            const oldCnt  = prev[key] ?? 0;
            for (let i = newCnt; i < oldCnt; i++) b.setVisibleAt(ids[i], false);
            prev[key] = newCnt;
        };

        // ── Монеты ─────────────────────────────────────────────────────────────
        let coinSparkIdx = 0;
        const sparkMesh  = coinSparkRef.current;

        for (let i = 0; i < coins.length; i++) {
            const c   = coins[i];
            const key = c.type === 'gold' ? 'coin_gold' : 'coin_red';

            if (c.collected) {
                if (c.collectTime === undefined) {
                    c.collectTime = time;
                    activateBurst(c.x, c.floatY ?? 0.65, c.z, time);
                }
                const t = (time - c.collectTime) / COLLECT_ANIM;
                if (t >= 1) continue;
                const flyY  = (c.floatY ?? 0.65) + t * 1.2;
                const scale = Math.max(0, 1 + t * 0.8 - t * t * 1.6);
                temp.position.set(c.x, flyY, c.z);
                temp.rotation.set(0, c.spinY ?? 0, 0);
                temp.scale.setScalar(scale);
                temp.updateMatrix();
                show(key, temp.matrix);
            } else {
                const floatY = 0.65 + Math.sin(time * 2.2 + c.phase) * 0.12;
                const spinY  = time * 2.8 + c.phase;
                c.floatY = floatY; c.spinY = spinY;
                temp.position.set(c.x, floatY, c.z);
                temp.rotation.set(0, spinY, 0);
                temp.scale.setScalar(1);
                temp.updateMatrix();
                show(key, temp.matrix);

                // Idle искры
                if (sparkMesh) {
                    for (let j = 0; j < IDLE_PER_COIN; j++) {
                        const ph     = c.phase + j * (Math.PI * 2 / IDLE_PER_COIN);
                        const radius = 0.45 + Math.sin(time * 1.8 + ph * 1.3) * 0.1;
                        temp.position.set(
                            c.x + Math.cos(time * 1.4 + ph) * radius,
                            floatY + Math.sin(time * 2.5 + ph * 2) * 0.12,
                            c.z + Math.sin(time * 1.4 + ph) * radius,
                        );
                        temp.rotation.set(time + ph, time * 0.7, 0);
                        temp.scale.setScalar(0.4 + Math.abs(Math.sin(time * 3.0 + ph)) * 0.6);
                        temp.updateMatrix();
                        sparkMesh.setMatrixAt(coinSparkIdx++, temp.matrix);
                    }
                }
            }
        }

        // Burst-анимация при сборе монеты
        if (sparkMesh) {
            for (let bi = 0; bi < MAX_BURSTS; bi++) {
                const burst = burstPool[bi];
                if (!burst.active) continue;
                const age = time - burst.startTime;
                if (age >= BURST_LIFETIME) { burst.active = false; continue; }
                const t      = age / BURST_LIFETIME;
                const spread = 1 - (1-t)*(1-t)*(1-t);
                const scale  = (1 - t) * 2.0;
                if (scale <= 0.01) continue;
                for (let j = 0; j < BURST_COUNT; j++) {
                    const d = burst.dirs[j];
                    temp.position.set(burst.x + d.vx * spread, burst.y, burst.z + d.vz * spread);
                    temp.rotation.set(age * 4 + j, age * 2, 0);
                    temp.scale.setScalar(scale);
                    temp.updateMatrix();
                    sparkMesh.setMatrixAt(coinSparkIdx++, temp.matrix);
                }
            }
            sparkMesh.count = coinSparkIdx;
            if (coinSparkIdx > 0) sparkMesh.instanceMatrix.needsUpdate = true;
        }

        // ── Медали ─────────────────────────────────────────────────────────────
        let medalSparkIdx  = 0;
        const mSparkMesh   = medalSparkRef.current;

        for (let i = 0; i < medals.length; i++) {
            const m       = medals[i];
            const subtype = m.subtype ?? 'medal_part1';
            if (!POOL_CM[subtype]) continue;

            if (m.collected) {
                if (m.collectTime === undefined) m.collectTime = time;
                const t = (time - m.collectTime) / MEDAL_COLLECT_DURATION;
                if (t >= 1) continue;
                const flyY  = (m.floatY ?? 0.7) + t * 5.0;
                const scale = Math.max(0, 1.0 - t * t * 1.3);
                temp.position.set(m.x, flyY, m.z);
                temp.rotation.set(0, time * (8 + t * 12), 0);
                temp.scale.setScalar(scale);
                temp.updateMatrix();
                show(subtype, temp.matrix);
            } else {
                const floatY   = 0.7 + Math.sin(time * 1.4 + m.phase) * 0.18;
                const bobScale = 1.0 + Math.sin(time * 2.5 + m.phase) * 0.06;
                m.floatY = floatY;
                const swayX = Math.sin(time * 1.1 + m.phase) * 0.22;
                const swayZ = Math.cos(time * 0.9 + m.phase + 1.0) * 0.18;
                temp.position.set(m.x, floatY, m.z);
                temp.rotation.set(swayX, Math.PI, swayZ);
                temp.scale.setScalar(bobScale);
                temp.updateMatrix();
                show(subtype, temp.matrix);

                // Idle искры медали
                if (mSparkMesh) {
                    for (let j = 0; j < IDLE_SPARKS_PER_MEDAL; j++) {
                        const ph     = m.phase + j * (Math.PI * 2 / IDLE_SPARKS_PER_MEDAL);
                        const radius = 0.5 + Math.sin(time * 2.2 + ph * 1.5) * 0.12;
                        temp.position.set(
                            m.x + Math.cos(time * 1.6 + ph) * radius,
                            floatY + Math.sin(time * 3.0 + ph * 2.5) * 0.2,
                            m.z + Math.sin(time * 1.6 + ph) * radius,
                        );
                        temp.rotation.set(time + ph, time * 0.9, 0);
                        temp.scale.setScalar(0.5 + Math.abs(Math.sin(time * 3.5 + ph)) * 0.5);
                        temp.updateMatrix();
                        mSparkMesh.setMatrixAt(medalSparkIdx++, temp.matrix);
                    }
                }
            }
        }

        if (mSparkMesh) {
            mSparkMesh.count = medalSparkIdx;
            if (medalSparkIdx > 0) mSparkMesh.instanceMatrix.needsUpdate = true;
        }

        // Commit — скрываем неиспользованные слоты
        for (const k in POOL_CM) commit(k);
    });

    return (
        <>
            {batch && <primitive object={batch} />}
            <instancedMesh ref={coinSparkRef}  args={[coinSparkGeo,  coinSparkMat,  MAX_COIN_SPARKS]}  frustumCulled={false} />
            <instancedMesh ref={medalSparkRef} args={[medalSparkGeo, medalSparkMat, MAX_MEDAL_SPARKS]} frustumCulled={false} />
        </>
    );
}

useGLTF.preload('/models/coin.glb');
useGLTF.preload('/models/medal.glb');
