import * as THREE from 'three';
import gsap from 'gsap';
import { forwardRef, useImperativeHandle, useRef } from 'react';

// ── Дебрис — материалы модульного уровня (без opacity-анимации, можно шарить) ─
const _matHot  = new THREE.MeshBasicMaterial({ color: '#ff4400' });
const _matCold = new THREE.MeshBasicMaterial({ color: '#2d2d2d' });

// ── Геометрии — модульный уровень ─────────────────────────────────────────────
const _geoFlash = new THREE.SphereGeometry(1, 7, 5);
const _geoRing  = new THREE.RingGeometry(0.6, 1, 40);
const _geoDA    = new THREE.BoxGeometry(0.26, 0.26, 0.26);
const _geoDB    = new THREE.BoxGeometry(0.38, 0.14, 0.22);
const _geoDE    = new THREE.BoxGeometry(0.15, 0.40, 0.15);

const DEBRIS_DEFS = [
    { geo: _geoDA, mat: _matHot  }, { geo: _geoDB, mat: _matCold },
    { geo: _geoDE, mat: _matHot  }, { geo: _geoDA, mat: _matCold },
    { geo: _geoDB, mat: _matHot  }, { geo: _geoDE, mat: _matCold },
    { geo: _geoDA, mat: _matHot  }, { geo: _geoDB, mat: _matCold },
];

const ROT_RING  = [-Math.PI / 2, 0, 0];
const BURST_MAX = 3; // максимум слотов — хватит для C4 (3 взрыва)

// ── Анимация одного взрыва ────────────────────────────────────────────────────
function fireBurst(slot, x, z, scale) {
    const { group, flash, ring, debris, matFlash, matRing } = slot;
    if (!group) return;

    group.position.set(x, 0, z);

    // Вспышка
    if (flash) {
        gsap.killTweensOf(flash.scale);
        gsap.killTweensOf(matFlash);
        matFlash.opacity = 0.85;
        flash.scale.setScalar(0.1);
        gsap.to(flash.scale, { x: 2.2 * scale, y: 2.2 * scale, z: 2.2 * scale,
            duration: 0.13, ease: 'power4.out' });
        gsap.to(flash.scale, { x: 0, y: 0, z: 0,
            delay: 0.13, duration: 0.28, ease: 'power2.in' });
        gsap.to(matFlash, { opacity: 0, duration: 0.38 });
    }

    // Кольцо
    if (ring) {
        gsap.killTweensOf(ring.scale);
        gsap.killTweensOf(matRing);
        matRing.opacity = 0.9;
        ring.scale.setScalar(0.3);
        gsap.to(ring.scale, { x: 6 * scale, y: 6 * scale, z: 6 * scale,
            duration: 0.55, ease: 'power2.out' });
        gsap.to(matRing, { opacity: 0, duration: 0.55, ease: 'power2.in' });
    }

    // Дебрис
    debris?.children.forEach((mesh) => {
        gsap.killTweensOf(mesh.position);
        gsap.killTweensOf(mesh.rotation);
        gsap.killTweensOf(mesh.scale);

        mesh.position.set(0, 0.2, 0);
        mesh.scale.setScalar(1);

        const angle = Math.random() * Math.PI * 2;
        const dist  = (1.5 + Math.random() * 3.5) * scale;
        gsap.to(mesh.position, {
            x: Math.cos(angle) * dist, y: (0.6 + Math.random() * 2.8) * scale, z: Math.sin(angle) * dist,
            duration: 0.75, ease: 'power2.out',
        });
        gsap.to(mesh.position, { y: 0, delay: 0.45, duration: 0.38, ease: 'power2.in' });
        gsap.to(mesh.rotation, {
            x: (Math.random() - 0.5) * Math.PI * 5,
            y: (Math.random() - 0.5) * Math.PI * 5,
            duration: 0.85,
        });
        gsap.to(mesh.scale, { x: 0, y: 0, z: 0, delay: 0.5, duration: 0.34 });
    });
}

// ── Компонент ─────────────────────────────────────────────────────────────────
const ExplosionEffect = forwardRef(function ExplosionEffect(_, ref) {
    // Каждый слот — независимый набор мешей + собственные материалы для opacity
    const slotsRef = useRef(Array.from({ length: BURST_MAX }, () => ({
        group: null, flash: null, ring: null, debris: null,
        matFlash: new THREE.MeshBasicMaterial({
            color: '#ffe080', transparent: true, opacity: 0, depthWrite: false, side: THREE.BackSide,
        }),
        matRing: new THREE.MeshBasicMaterial({
            color: '#ff6600', transparent: true, opacity: 0, depthWrite: false, side: THREE.DoubleSide,
        }),
    })));

    useImperativeHandle(ref, () => ({
        trigger(x, z, options = {}) {
            const { scale = 1, bursts = 1, spread = 2 } = options;
            const slots = slotsRef.current;
            for (let b = 0; b < Math.min(bursts, BURST_MAX); b++) {
                const bx = b === 0 ? x : x + (Math.random() - 0.5) * spread * 2;
                const bz = b === 0 ? z : z + (Math.random() - 0.5) * spread * 2;
                const bs = b === 0 ? scale : scale * (0.55 + Math.random() * 0.35);
                gsap.delayedCall(b * 0.22, () => fireBurst(slots[b], bx, bz, bs));
            }
        },
    }));

    return (
        <group>
            {slotsRef.current.map((slot, si) => (
                // position Y=-2000 прячет дебрис под картой до первого trigger()
                <group key={si} ref={el => { slot.group = el; }} position={[0, -2000, 0]}>
                    <mesh ref={el => { slot.flash = el; }} geometry={_geoFlash} material={slot.matFlash} />
                    <mesh ref={el => { slot.ring  = el; }} geometry={_geoRing}  material={slot.matRing}  rotation={ROT_RING} />
                    <group ref={el => { slot.debris = el; }}>
                        {DEBRIS_DEFS.map((d, i) => <mesh key={i} geometry={d.geo} material={d.mat} />)}
                    </group>
                </group>
            ))}
        </group>
    );
});

export default ExplosionEffect;
