import { useFrame } from '@react-three/fiber';
import { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { useWorld } from '../Logic/GameWorldContext';
import { WATER_Y, WATER_BOTTOM_OFFSET } from '../Logic/constants';
import WaterRowMaterialClass, { waterRowGeometry, setWaterTime } from './WaterRowMaterial';
import { causticsGeo, causticsMaterial, updateCausticsFrame, bottomGeo, bottomMaterial } from './WaterBottomLayers';

const BOTTOM_Y       = WATER_Y - WATER_BOTTOM_OFFSET;
const MAX_WATER_ROWS = 22; // MAP_WINDOW_SIZE=40, water=30% → ~12 avg, worst-case ~20 rows

// Reusable Object3D + quaternion for building instance matrices
const _temp    = new THREE.Object3D();
const _rotQuat = new THREE.Quaternion().setFromAxisAngle(new THREE.Vector3(1, 0, 0), -Math.PI / 2);

export default function WaterEffectsView() {
    const world = useWorld();

    // Create the 3 InstancedMesh objects and the shared water surface material once
    const [meshes, setMeshes] = useState(null);
    const waterMatRef = useRef(null);

    useEffect(() => {
        const mat = new WaterRowMaterialClass();
        mat.transparent = true;
        mat.depthWrite  = false;
        waterMatRef.current = mat;

        const surface = new THREE.InstancedMesh(waterRowGeometry, mat, MAX_WATER_ROWS);
        surface.renderOrder     = 1;
        surface.frustumCulled   = false;
        surface.count           = 0;

        const bot = new THREE.InstancedMesh(bottomGeo, bottomMaterial, MAX_WATER_ROWS);
        bot.frustumCulled = false;
        bot.count         = 0;

        const caust = new THREE.InstancedMesh(causticsGeo, causticsMaterial, MAX_WATER_ROWS);
        caust.renderOrder   = 2;
        caust.frustumCulled = false;
        caust.count         = 0;

        setMeshes({ surface, bot, caust });

        return () => {
            mat.dispose();
            surface.dispose();
            bot.dispose();
            caust.dispose();
        };
    }, []);

    useFrame((state) => {
        const t = state.clock.elapsedTime;
        setWaterTime(t);
        updateCausticsFrame(t);
        bottomMaterial.uniforms.uTime.value = t;

        const wMat = waterMatRef.current;
        if (wMat) {
            wMat.uniforms.uTime.value = t;
        }

        if (!meshes || !world.watersDirty) return;
        world.watersDirty = false;

        const sorted = Array.from(world.waters).sort((a, b) => a - b);
        const count  = Math.min(sorted.length, MAX_WATER_ROWS);

        // Preload rotation into _temp once; position changes per row
        _temp.quaternion.copy(_rotQuat);
        _temp.scale.set(1, 1, 1);

        for (let i = 0; i < count; i++) {
            const z = sorted[i];

            // Bottom layer
            _temp.position.set(0, BOTTOM_Y, z);
            _temp.updateMatrix();
            meshes.bot.setMatrixAt(i, _temp.matrix);

            // Water surface
            _temp.position.set(0, WATER_Y, z);
            _temp.updateMatrix();
            meshes.surface.setMatrixAt(i, _temp.matrix);

            // Caustics (slightly above surface to avoid z-fighting)
            _temp.position.set(0, WATER_Y + 0.01, z);
            _temp.updateMatrix();
            meshes.caust.setMatrixAt(i, _temp.matrix);
        }

        meshes.bot.count     = count;
        meshes.surface.count = count;
        meshes.caust.count   = count;

        meshes.bot.instanceMatrix.needsUpdate     = true;
        meshes.surface.instanceMatrix.needsUpdate = true;
        meshes.caust.instanceMatrix.needsUpdate   = true;
    });

    if (!meshes) return null;
    return (
        <>
            <primitive object={meshes.bot} />
            <primitive object={meshes.surface} />
            <primitive object={meshes.caust} />
        </>
    );
}
