import { StrictMode } from 'react'
import { createRoot } from 'react-dom/client'
import './style.css'
import Game from './Game/Game'

// Prevent double-tap zoom on iOS Safari (ignores viewport user-scalable on iOS 10+)
let lastTouchEnd = 0;
document.addEventListener('touchend', function(e) {
    const now = Date.now();
    if (now - lastTouchEnd < 300) {
        e.preventDefault();
    }
    lastTouchEnd = now;
}, { passive: false });

// Auto-reset zoom if browser zoomed anyway (e.g. double-tap slipped through)
const viewportMeta = document.querySelector('meta[name="viewport"]');
function resetZoom() {
    viewportMeta.setAttribute('content', 'width=device-width, initial-scale=1, maximum-scale=1, minimum-scale=1, user-scalable=no, viewport-fit=cover');
}
if (window.visualViewport) {
    window.visualViewport.addEventListener('resize', () => {
        if (window.visualViewport.scale > 1.01) resetZoom();
    });
}

createRoot(document.getElementById('root')).render(
    <StrictMode>
        <Game />
    </StrictMode>
)